globalThis.__BQ = {"urinerGenel":{"lise":{"kolay":[{"q":"İnsanda boşaltım sistemini oluşturan organ grubunda kaç böbrek bulunur?","steps":[{"t":"Boşaltım sisteminin tanımı","a":"İdrar üreten organlar","d":"Boşaltım sistemi, kanı süzerek metabolik atıkları idrar biçiminde dışarı atan organlardan oluşur. Bu sistemin asıl süzme görevini böbrekler üstlenir. Diğer yapılar idrarın taşınması ve depolanmasından sorumludur."},{"t":"Böbrek sayısı","a":"2 böbrek","d":"İnsanda omurganın iki yanında, karın boşluğunun arka üst bölümünde simetrik olarak yerleşmiş iki böbrek bulunur. Bu çift organ yapısı, biri zarar görse bile diğerinin görevi sürdürebilmesini sağlar. Böbrekler boşaltımın merkezidir."}],"ans":"2 (iki) böbrek bulunur."},{"q":"İdrarın vücuttan atılması sırasında izlediği yolun doğru sırası nedir?","steps":[{"t":"Yapıların görevi","a":"Üretim, taşıma, depo, dışarı","d":"Böbrek idrarı üretir, üreter idrarı taşır, mesane depolar, üretra ise dışarı boşaltır. Her yapı bu zincirde belirli bir basamağı üstlenir. Sıralama bu işlevlere göre belirlenir."},{"t":"Akış sırasının yazılması","a":"Böbrek→üreter→mesane→üretra","d":"İdrar önce böbrekte oluşur, ardından üreter aracılığıyla mesaneye iletilir. Mesanede biriktirildikten sonra üretra yoluyla vücut dışına atılır. Bu tek yönlü akış idrar yolunu tanımlar."}],"ans":"Böbrek → üreter → mesane → üretra."},{"q":"Boşaltım sisteminde idrarı geçici olarak depolayan organ hangisidir?","steps":[{"t":"Depolama görevi","a":"İdrar biriktirme ihtiyacı","d":"Böbrekler sürekli idrar üretir, ancak boşaltım belirli aralıklarla yapılır. Bu nedenle üretilen idrarın bir süre saklanması gerekir. Saklama işini elastik duvarlı bir kese görür."},{"t":"Organın belirlenmesi","a":"Mesane","d":"İdrar kesesi olarak da bilinen mesane, kaslı ve esnek duvarları sayesinde dolarken genişler. Belirli bir doluluğa ulaştığında boşaltma uyarısı oluşur. Böylece idrar düzenli aralıklarla dışarı atılır."}],"ans":"Mesane (idrar kesesi)."},{"q":"Protein metabolizması sonucu oluşan ve böbrekle atılan başlıca azotlu atık nedir?","steps":[{"t":"Atığın kaynağı","a":"Proteinlerin yıkımı","d":"Proteinler aminoasitlere parçalandığında açığa amonyak çıkar. Amonyak hücreler için çok zehirli olduğundan vücutta birikmesine izin verilmez. Bu nedenle daha az zararlı bir bileşiğe dönüştürülür."},{"t":"Atığın belirlenmesi","a":"Üre","d":"Karaciğer amonyağı üreye çevirir ve üre kana verilir. Böbrekler kandaki üreyi süzerek idrarla dışarı atar. İnsanda azotlu atıkların büyük kısmı üre biçimindedir."}],"ans":"Üre."},{"q":"Vücutta boşaltıma yardımcı olan ve su ile tuz atan organ hangisidir?","steps":[{"t":"Yardımcı organlar","a":"Böbrek dışı atım","d":"Boşaltımın tamamı böbreklerle yapılmaz; bazı organlar da atık atımına katkıda bulunur. Deri, akciğer ve karaciğer yardımcı boşaltım organlarıdır. Her biri farklı atıkları uzaklaştırır."},{"t":"Su-tuz atan organ","a":"Deri","d":"Deride bulunan ter bezleri terle birlikte su, tuz ve az miktarda üre atar. Bu nedenle deri hem ısı düzenler hem de boşaltıma yardım eder. Terleme yardımcı bir atım yoludur."}],"ans":"Deri (ter bezleriyle)."},{"q":"Akciğerlerin boşaltıma katkısı hangi atık maddenin atılmasıyla olur?","steps":[{"t":"Akciğerin işlevi","a":"Gaz alışverişi","d":"Akciğerler solunum sırasında oksijeni alıp kana verir. Aynı zamanda hücresel solunumda üretilen bir gazı dışarı atar. Bu gaz aynı zamanda bir metabolik atıktır."},{"t":"Atılan atık","a":"Karbondioksit (ve su buharı)","d":"Hücreler enerji üretirken karbondioksit oluşturur ve bu gaz kana geçer. Akciğerler karbondioksiti soluk verme ile dışarı atar. Ayrıca soluk havasıyla bir miktar su buharı da uzaklaşır."}],"ans":"Karbondioksit (ve su buharı)."},{"q":"İdrarı mesaneden vücut dışına taşıyan kanal hangisidir?","steps":[{"t":"Mesanenin sonrası","a":"Son atım yolu","d":"Mesanede biriken idrar, boşaltma sırasında tek bir kanaldan dışarı verilir. Bu kanal idrar yolunun en son bölümüdür. Böbrek ve üreterden farklı olarak doğrudan dış ortama açılır."},{"t":"Kanalın adı","a":"Üretra","d":"Üretra, mesaneden başlayıp vücut dışına açılan boşaltım kanalıdır. Mesane kası kasıldığında idrar üretra boyunca ilerleyerek atılır. Böylece boşaltım tamamlanmış olur."}],"ans":"Üretra."},{"q":"Böbrekte üretilen idrarı mesaneye taşıyan yapı hangisidir?","steps":[{"t":"Üretim sonrası taşıma","a":"Böbrek ile mesane arası","d":"İdrar böbrekte oluştuktan sonra depolanacağı mesaneye ulaşmalıdır. Bu iki organ arasında bağlantıyı sağlayan bir boru bulunur. Boru idrarı tek yönde iletir."},{"t":"Yapının adı","a":"Üreter","d":"Üreter, her böbrekten çıkıp mesaneye uzanan ince kaslı bir kanaldır. Kas hareketleriyle idrarı aşağıya doğru iter. İnsanda iki böbreğe karşılık iki üreter bulunur."}],"ans":"Üreter."},{"q":"Karaciğerin boşaltıma katkısı en çok hangi açıdan önemlidir?","steps":[{"t":"Karaciğerin rolü","a":"Zehir dönüşümü","d":"Karaciğer vücudun ana kimyasal işleme merkezidir ve zararlı maddeleri etkisizleştirir. Boşaltım açısından en kritik görevi amonyağa karşıdır. Bu görev böbreklerin işini kolaylaştırır."},{"t":"Üre üretimi","a":"Amonyağı üreye çevirir","d":"Karaciğer zehirli amonyağı daha az zararlı olan üreye dönüştürür. Oluşan üre kana verilip böbreklerle atılır. Ayrıca karaciğer yaşlı alyuvarların yıkım atıklarını da işler."}],"ans":"Amonyağı üreye dönüştürmesi."},{"q":"İnsanda kaç tane üreter bulunur?","steps":[{"t":"Böbrek-üreter ilişkisi","a":"Her böbreğe bir kanal","d":"Her böbrekte oluşan idrar ayrı bir kanalla mesaneye gönderilir. Böbrek sayısı kadar taşıma kanalı bulunur. Bu eşleşme idrar yolunun simetrisini oluşturur."},{"t":"Sayının belirlenmesi","a":"2 üreter","d":"İki böbrek bulunduğu için her birine bağlı birer üreter vardır. Böylece toplamda iki üreter mesaneye açılır. Üretra ise tek olduğundan üreterle karıştırılmamalıdır."}],"ans":"2 (iki) üreter."},{"q":"Boşaltım sisteminin temel görevi nedir?","steps":[{"t":"Atıkların sorunu","a":"Metabolizma atık üretir","d":"Hücreler enerji ve madde dönüşümü sırasında sürekli atık üretir. Bu atıklar kanda birikirse vücut için zehir etkisi yapar. Bu nedenle düzenli olarak uzaklaştırılmaları gerekir."},{"t":"Görevin tanımı","a":"Atık ve fazla suyu atma","d":"Boşaltım sistemi kandaki azotlu atıkları, fazla suyu ve tuzları süzerek dışarı atar. Aynı zamanda kanın bileşimini dengede tutar. Böylece iç ortam kararlılığı korunur."}],"ans":"Metabolik atıkları ve fazla suyu süzüp atmak."},{"q":"Ürik asit hangi madde grubunun yıkım atığıdır?","steps":[{"t":"Atığın kaynağı","a":"Nükleik asit yıkımı","d":"Hücrelerdeki DNA ve RNA gibi nükleik asitler yıkıldığında azotlu kalıntılar oluşur. Bu kalıntılardan biri ürik asittir. Ürik asit kanda taşınıp boşaltımla atılır."},{"t":"Atığın belirlenmesi","a":"Ürik asit","d":"Ürik asit, nükleik asitlerin (pürin bazlarının) parçalanmasıyla üretilen azotlu bir atıktır. İnsanda idrarla atılır. Fazla birikmesi eklemlerde sorunlara yol açabilir."}],"ans":"Nükleik asitlerin yıkımı."},{"q":"Boşaltım sistemini oluşturan dört temel yapı hangileridir?","steps":[{"t":"Yapıların gruplanması","a":"Süzme ve idrar yolu","d":"Sistem, idrarı üreten organlar ile bu idrarı ileten yapılardan oluşur. Süzme görevini böbrekler yapar. Geri kalan yapılar idrarı taşır, depolar ve atar."},{"t":"Yapıların sayılması","a":"Böbrek, üreter, mesane, üretra","d":"Boşaltım sisteminin dört temel bileşeni böbrekler, üreterler, mesane ve üretradır. Böbrek süzme, üreter taşıma, mesane depolama ve üretra atma görevi görür. Birlikte idrar yolunu oluştururlar."}],"ans":"Böbrekler, üreterler, mesane ve üretra."},{"q":"Kreatinin hangi dokudaki metabolizmanın atığıdır?","steps":[{"t":"Atığın kaynağı","a":"Kas çalışması","d":"Kaslarda enerji deposu olarak kullanılan kreatin fosfat yıkıldığında bir atık ortaya çıkar. Bu atık kana karışır. Kan dolaşımıyla böbreklere ulaşır."},{"t":"Atığın belirlenmesi","a":"Kreatinin","d":"Kreatinin, kas dokusundaki kreatin metabolizmasının azotlu atık ürünüdür. Böbreklerle süzülerek idrarla atılır. Kandaki düzeyi böbrek sağlığının göstergesi olarak kullanılır."}],"ans":"Kas dokusu (kreatin metabolizması)."},{"q":"İnsanda azotlu atıkların büyük çoğunluğu hangi madde biçiminde atılır?","steps":[{"t":"Atık çeşitleri","a":"Üre, ürik asit, kreatinin","d":"İnsanda başlıca azotlu atıklar üre, ürik asit ve kreatinindir. Bunların oranları farklıdır. En çok atılan bileşik baskın atık kabul edilir."},{"t":"Baskın atık","a":"Üre","d":"İnsanda atılan azotlu atığın büyük kısmını üre oluşturur. Üre, proteinlerden gelen amonyağın karaciğerde dönüştürülmesiyle üretilir. Bu nedenle insan üreotelik bir canlı sayılır."}],"ans":"Üre."}],"zor":[{"q":"Bir kişide her iki böbrek de işlevini yitirirse kanda en hızlı artması beklenen madde grubu hangisidir, neden?","steps":[{"t":"Böbreğin işlevi","a":"Atıkları kandan uzaklaştırma","d":"Böbrekler kandaki azotlu atıkları sürekli süzerek idrara verir. İşlev yitirilirse bu süzme durur. Atıklar artık vücuttan uzaklaştırılamaz."},{"t":"Birikimin sonucu","a":"Azotlu atıklar kanda birikir","d":"Süzme durunca üre, ürik asit ve kreatinin kanda hızla yükselir. Bu maddeler hücreler için zehirleyicidir. Kanda artışları böbrek yetmezliğinin ilk göstergesidir."},{"t":"Genel değerlendirme","a":"Azotlu atık birikimi","d":"Atık birikimi iç ortam dengesini bozar ve zehirlenmeye yol açar. Diyaliz gibi yapay süzme yöntemleri gerekebilir. Böylece azotlu atıkların atımı yeniden sağlanır."}],"ans":"Azotlu atıklar (üre, ürik asit, kreatinin) birikir."},{"q":"Çok sıcak bir ortamda yoğun terleyen kişide böbreklerin ürettiği idrar miktarının azalması nasıl açıklanır?","steps":[{"t":"Terlemenin etkisi","a":"Deriyle su kaybı","d":"Sıcak ortamda deri terle birlikte bol miktarda su atar. Bu su kaybı kanın su içeriğini düşürür. Vücut su açığı oluşturmamaya çalışır."},{"t":"Böbreğin tepkisi","a":"Suyu geri tutar","d":"Su kaybını dengelemek için böbrekler daha çok su geri emer. Böylece idrarla atılan su azalır. Atılan idrar daha az ve daha koyu olur."},{"t":"Bütünleşik sonuç","a":"İdrar miktarı azalır","d":"Deri ve böbrek birlikte su dengesini korur; biri çok su atınca diğeri tutar. Bu nedenle terlenen günlerde idrar azalır. Yardımcı ve asıl boşaltım organları uyum içinde çalışır."}],"ans":"Terle çok su kaybedildiğinden böbrek su tutar, idrar azalır."},{"q":"Karaciğeri ağır hasar görmüş bir hastada kandaki amonyak düzeyinin yükselmesi neden tehlikelidir?","steps":[{"t":"Karaciğerin görevi","a":"Amonyağı üreye çevirir","d":"Karaciğer, protein yıkımından gelen zehirli amonyağı daha az zararlı üreye dönüştürür. Hasarlı karaciğer bu dönüşümü yeterince yapamaz. Sonuçta amonyak işlenmeden kanda kalır."},{"t":"Amonyağın etkisi","a":"Hücrelere toksik","d":"Amonyak özellikle sinir hücreleri için çok zehirlidir. Kandaki yüksek amonyak beyin işlevlerini bozar. Bu durum bilinç bulanıklığına yol açabilir."},{"t":"Sonuç","a":"Zehirlenme tehlikesi","d":"Üreye çevrilemeyen amonyak böbrekle de kolayca atılamadığından birikir. Bu birikim sinir sistemini etkileyerek yaşamı tehdit eder. Bu nedenle karaciğer boşaltıma yardımcı kritik bir organdır."}],"ans":"Amonyak üreye çevrilemez, kanda birikip sinir sistemine zehir etkisi yapar."},{"q":"Üreterlerden birinin taşla tıkanması durumunda o böbrekte ne tür bir sorun oluşması beklenir?","steps":[{"t":"Üreterin görevi","a":"İdrarı mesaneye taşır","d":"Üreter, böbrekte oluşan idrarı mesaneye ileten kanaldır. Tıkanırsa idrarın akışı durur. İdrar üretildiği yerde geri birikmeye başlar."},{"t":"Geri birikme","a":"İdrar böbrekte birikir","d":"Akış durunca idrar böbrek havuzcuğunda toplanır ve basınç artar. Bu basınç böbrek dokusunu zorlar. Genişleme ve hasar gelişebilir."},{"t":"Sonuç","a":"Böbrekte basınç ve hasar","d":"Tıkanıklık sürerse böbrek şişer ve süzme işlevi bozulur. Diğer böbrek görev fazlasını üstlenmeye çalışır. Tedavi edilmezse o böbrek kalıcı zarar görebilir."}],"ans":"İdrar geri birikir, böbrekte basınç artışı ve hasar oluşur."},{"q":"Çok az protein içeren bir beslenme uygulayan kişide idrardaki üre miktarının düşmesi nasıl açıklanır?","steps":[{"t":"Ürenin kaynağı","a":"Protein yıkımı","d":"Üre, proteinlerden gelen aminoasitlerin yıkımı sonucu oluşan amonyaktan üretilir. Beslenmede protein azalırsa yıkılacak aminoasit de azalır. Bu, üre üretiminin temelini etkiler."},{"t":"Üretimin azalması","a":"Daha az üre oluşur","d":"Az protein alımıyla karaciğerde daha az amonyak işlenir. Dolayısıyla kana daha az üre verilir. Kandaki üre derişimi düşer."},{"t":"Sonuç","a":"İdrarda üre azalır","d":"Kanda az olan üre, böbrekle de daha az miktarda atılır. Bu yüzden idrardaki üre düzeyi düşer. Beslenme ile boşaltım atıkları arasındaki ilişki böyle kurulur."}],"ans":"Az protein alımıyla az üre üretilir, idrarda üre azalır."},{"q":"Boşaltım sisteminin iç denge (homeostazi) ile ilişkisi hangi yönlerden kurulur?","steps":[{"t":"İç dengenin tanımı","a":"Kararlı iç ortam","d":"Homeostazi, vücudun iç ortamını sabit tutma yeteneğidir. Su, tuz ve atık dengesi bu kararlılığın parçasıdır. Boşaltım sistemi bu dengelerin korunmasında etkilidir."},{"t":"Böbreğin katkısı","a":"Su, tuz, atık ayarı","d":"Böbrekler fazla suyu, tuzu ve atığı atarken gerekli olanları geri tutar. Böylece kanın bileşimi sabit kalır. Kanın pH değeri de bu sayede dengelenir."},{"t":"Sonuç","a":"Homeostaziye katkı","d":"Boşaltım sistemi atık atımı, su-tuz dengesi ve pH ayarıyla iç dengeyi korur. Bu işlevler bozulursa vücut kimyası bozulur. Bu nedenle boşaltım homeostazinin temel taşlarından biridir."}],"ans":"Su-tuz dengesi, atık atımı ve pH ayarı yoluyla iç dengeyi korur."},{"q":"İnsan idrarında normalde proteine rastlanmamasının boşaltım sistemiyle ilişkisi nedir?","steps":[{"t":"Süzme ölçütü","a":"Molekül büyüklüğü","d":"Böbreklerdeki süzme yapısı yalnızca küçük molekülleri geçirir. Büyük moleküller bu engelden geçemez. Proteinler büyük moleküller olduğundan süzülmez."},{"t":"Proteinin durumu","a":"Kanda kalır","d":"Süzülmeyen proteinler kandan idrara geçemez ve dolaşımda kalır. Bu nedenle sağlıklı bir insanın idrarında protein bulunmaz. İdrarda protein görülmesi süzme yapısının hasarını gösterir."},{"t":"Sonuç","a":"İdrarda protein olmaması normaldir","d":"Sağlıklı süzme yapısı proteinleri tutar, atıkları ve fazla suyu geçirir. Bu seçicilik vücut için yararlı maddelerin kaybını önler. Bu yüzden idrarda protein olmaması beklenen durumdur."}],"ans":"Büyük protein molekülleri süzülmez, idrara geçmez."},{"q":"Bir kişinin günlük su tüketimi belirgin biçimde artarsa boşaltım sisteminde ne değişir?","steps":[{"t":"Fazla suyun durumu","a":"Kanda su artışı","d":"Fazla içilen su bağırsaktan emilerek kana karışır. Bu durum kanın su miktarını yükseltir. Vücut bu fazlalığı dengelemek ister."},{"t":"Böbreğin tepkisi","a":"Daha az su geri emer","d":"Böbrekler fazla suyu atmak için geri emilimi azaltır. Böylece idrarla daha çok su uzaklaştırılır. İdrar miktarı artar ve seyrelir."},{"t":"Sonuç","a":"İdrar miktarı artar","d":"Çok su içilince idrar bol ve açık renkli olur. Böylece kanın su dengesi korunur. Boşaltım sistemi su fazlasını ayarlayan temel yapıdır."}],"ans":"İdrar miktarı artar ve idrar seyrelir (açık renkli olur)."},{"q":"Akciğer ve deri olmasaydı böbreklerin yükünün artacağı söylenebilir mi, açıklayınız.","steps":[{"t":"Yardımcı organların payı","a":"Atıkların paylaşımı","d":"Akciğer karbondioksit ve su buharı atarken deri terle su, tuz ve az üre atar. Bu organlar böbreklerin işinin bir kısmını üstlenir. Atık atımı çeşitli yollara dağıtılır."},{"t":"Yardımcı organ kaybı","a":"Atıklar tek yola yığılır","d":"Bu yardımcı yollar olmasaydı bütün atık atımı böbreklere kalırdı. Özellikle su ve tuz atımı yükü artardı. Böbreklerin çalışma yükü belirgin biçimde yükselirdi."},{"t":"Sonuç","a":"Böbrek yükü artar","d":"Yardımcı boşaltım organları olmadan böbrekler daha fazla su, tuz ve atık atmak zorunda kalır. Bu, böbrekleri zorlar ve dengeyi zayıflatır. Bu nedenle yardımcı organlar boşaltımı paylaşan önemli yapılardır."}],"ans":"Evet; yardımcı organlar olmasa tüm atık yükü böbreklere biner."},{"q":"İdrar yolu enfeksiyonunun üretradan başlayıp mesaneye, oradan böbreğe ilerleyebilmesi hangi yapısal özellikle ilişkilidir?","steps":[{"t":"İdrar yolunun yapısı","a":"Birbirine bağlı kanallar","d":"Üretra, mesane, üreter ve böbrek birbirine açılan tek bir yol oluşturur. Bu yol idrarın akışı için sürekli bağlantılıdır. Bağlantı boşaltıma uygun bir geometri sağlar."},{"t":"Enfeksiyonun yayılımı","a":"Aşağıdan yukarı ilerleme","d":"Dıştan giren mikroplar üretradan mesaneye, oradan üretere ve böbreğe ulaşabilir. Çünkü yapılar açık bir kanal sistemiyle birbirine bağlıdır. Akışın tersine yayılım mümkündür."},{"t":"Sonuç","a":"Sürekli bağlantılı yol","d":"İdrar yolu organlarının ardışık ve açık bağlantısı enfeksiyonun yukarı tırmanmasına olanak verir. Bu nedenle alt yol enfeksiyonları ihmal edilmemelidir. Tedavi edilmezse böbreğe ulaşabilir."}],"ans":"Organların ardışık ve açık bir kanal sistemiyle bağlı olması."},{"q":"Üreden farklı olarak ürik asidin az suyla atılabilmesi hangi canlılar için avantaj sağlar?","steps":[{"t":"Atıkların su gereksinimi","a":"Üre çok su ister","d":"Üre suda kolay çözündüğü için atılırken bol su gerektirir. Ürik asit ise az çözünür ve macunsu biçimde atılabilir. Bu fark su kullanımını değiştirir."},{"t":"Su tasarrufu","a":"Ürik asit su tutar","d":"Ürik asit atılırken çok az su kaybı olur. Bu, su kaynağı sınırlı ortamlarda yaşam için elverişlidir. Kuş ve sürüngenler bu atığı kullanır."},{"t":"Sonuç","a":"Susuz ortam canlıları","d":"Ürik asit atımı, su kaybını en aza indirdiği için kurak ortam ve yumurta içi gelişim için avantajlıdır. İnsanda baskın atık üre olduğundan bu avantaj sınırlıdır. Atık türü yaşam ortamıyla ilişkilidir."}],"ans":"Su kaybını azalttığı için kurak ortam canlılarına avantaj sağlar."},{"q":"Bol tuzlu yiyecek tüketen bir kişide susama hissinin artması boşaltım açısından nasıl yorumlanır?","steps":[{"t":"Tuzun etkisi","a":"Kanda tuz derişimi artar","d":"Fazla tuz alımı kandaki tuz derişimini yükseltir. Vücut bu derişimi normale çekmek ister. Bunun için suya gereksinim duyar."},{"t":"Su talebi","a":"Susama uyarısı","d":"Yükselen tuz derişimi beyni uyararak susama hissi oluşturur. İçilen su kanı seyreltir. Böylece tuz dengesi yeniden kurulmaya çalışılır."},{"t":"Böbreğin rolü","a":"Fazla tuzu atar","d":"Böbrekler kandaki fazla tuzu süzerek idrarla atar; bunun için su da gerekir. Bu nedenle hem su içilir hem de tuz atımı için idrar üretilir. Su-tuz dengesi böbrek ile beslenme arasında kurulur."}],"ans":"Tuz derişimi artar, su ile dengelenir ve böbrek fazla tuzu atar."},{"q":"Diyaliz makinesinin görevi boşaltım sisteminin hangi organının işlevini taklit eder?","steps":[{"t":"Diyalizin amacı","a":"Kanı temizleme","d":"Diyaliz, böbrekleri çalışmayan hastaların kanındaki atıkları dışarıdan temizleyen bir yöntemdir. Kan bir cihazdan geçirilerek süzülür. Atıklar ve fazla su uzaklaştırılır."},{"t":"Taklit edilen organ","a":"Böbrek","d":"Diyaliz, kandaki üre ve fazla suyu süzdüğü için böbreklerin süzme işlevini taklit eder. Mesane veya üreter görevini üstlenmez. Asıl amaç kanı atıklardan arındırmaktır."},{"t":"Sonuç","a":"Böbrek işlevini üstlenir","d":"Böbrek yetmezliğinde diyaliz, kanı süzme görevini geçici olarak yerine getirir. Böylece azotlu atıkların birikmesi önlenir. Bu sayede hasta yaşamını sürdürebilir."}],"ans":"Böbreğin (kanı süzme) işlevini."},{"q":"Boşaltım atığı olarak üre üreten insan ile amonyak atan bir balık arasındaki temel fark suyla nasıl ilişkilidir?","steps":[{"t":"Amonyağın özelliği","a":"Çok zehirli, çok su gerektirir","d":"Amonyak çok zehirli olduğundan hemen seyreltilerek atılmalıdır. Bu da bol su gerektirir. Suda yaşayan canlılar için bu sorun değildir."},{"t":"Ürenin özelliği","a":"Daha az zehirli, az su","d":"Üre amonyağa göre daha az zehirlidir ve daha az suyla atılabilir. Karada yaşayan insan için su tasarrufu önemlidir. Bu nedenle insan amonyak yerine üre üretir."},{"t":"Sonuç","a":"Yaşam ortamı belirler","d":"Bol suyla çevrili balık amonyağı doğrudan atabilirken, karasal insan suyu korumak için üre üretir. Atık türü, su kaynağına ve yaşam ortamına göre değişir. Bu evrimsel bir uyumdur."}],"ans":"Balık bol suda amonyak atar, su gerektiren bu atık insan için uygun değildir; insan üre üretir."},{"q":"Bir spor karşılaşmasından sonra kasları yoğun çalışan sporcunun kanındaki kreatinin düzeyinin yükselmesi nasıl açıklanır?","steps":[{"t":"Kreatininin kaynağı","a":"Kas metabolizması","d":"Kreatinin, kaslardaki kreatin fosfatın yıkımından oluşan azotlu bir atıktır. Kas çalışması arttıkça bu yıkım da artar. Üretilen kreatinin kana karışır."},{"t":"Yoğun egzersiz etkisi","a":"Daha çok atık üretilir","d":"Yoğun egzersizde kaslar çok enerji harcar ve kreatin fosfat hızla yıkılır. Bu da kreatinin üretimini artırır. Kandaki kreatinin geçici olarak yükselir."},{"t":"Sonuç","a":"Kanda kreatinin artar","d":"Egzersiz sonrası böbrekler bu fazla kreatinini süzerek atana kadar kanda düzeyi yüksek kalır. Bu artış sağlıklı kişide geçicidir. Sürekli yüksek değer böbrek sorununu düşündürür."}],"ans":"Yoğun kas çalışması kreatin yıkımını artırır, kreatinin yükselir."}]}},"bobrekYapi":{"lise":{"kolay":[{"q":"Böbreğin dış görünümü hangi nesneye benzetilir?","steps":[{"t":"Dış biçim","a":"Kıvrımlı kenar","d":"Böbreğin bir kenarı dışa doğru kavislidir, diğer kenarı içe doğru çöküktür. Bu çukur bölgeye damarlar ve üreter bağlanır. Bu görünüm onu belirgin bir şekle sokar."},{"t":"Benzetme","a":"Fasulye tanesi","d":"Böbreğin kavisli ve girintili biçimi fasulye tanesine benzetilir. Bu nedenle böbrek şekli yaygın olarak fasulye biçimi diye anılır. Girintili bölge böbrek kapısı olarak adlandırılır."}],"ans":"Fasulye tanesine."},{"q":"Böbreğin dıştan içe doğru ilk (en dış) bölgesi hangisidir?","steps":[{"t":"İç yapının katmanları","a":"Dıştan içe sıralı bölgeler","d":"Böbrek kesildiğinde dıştan içe doğru farklı bölgeler görülür. En dışta bir kabuk bölgesi bulunur. Daha içte öz ve havuzcuk yer alır."},{"t":"En dış bölge","a":"Kabuk (korteks)","d":"Böbreğin en dış bölümü kabuk (korteks) olarak adlandırılır. Burada nefronların süzme yapıları yoğun olarak bulunur. Kabuk bölgesi öz bölgesinden daha açık renklidir."}],"ans":"Kabuk (korteks)."},{"q":"Böbreğin orta bölgesinde yer alan ve piramitlerin bulunduğu bölge hangisidir?","steps":[{"t":"Orta katman","a":"Kabuğun altı","d":"Kabuğun hemen altında daha koyu görünen bir bölge bulunur. Bu bölgede koni biçimli yapılar yer alır. Bu yapılar idrarın toplandığı kanalları içerir."},{"t":"Bölgenin adı","a":"Öz (medulla)","d":"Böbreğin orta bölgesi öz (medulla) olarak adlandırılır. Burada böbrek piramitleri bulunur. Piramitlerin uçları havuzcuğa doğru yönelir."}],"ans":"Öz (medulla)."},{"q":"İdrarın böbrekten çıkmadan önce toplandığı boşluk hangisidir?","steps":[{"t":"Toplanma noktası","a":"Üreter öncesi boşluk","d":"Nefronlarda oluşan idrar toplama kanallarıyla bir araya gelir. Bu idrar üretere geçmeden önce ortak bir boşlukta toplanır. Bu boşluk böbreğin iç bölümündedir."},{"t":"Boşluğun adı","a":"Böbrek havuzcuğu (pelvis)","d":"İdrarın toplandığı huni biçimli boşluğa böbrek havuzcuğu (pelvis) denir. Buradan idrar üretere geçer. Havuzcuk, böbrek ile üreter arasındaki geçiş bölgesidir."}],"ans":"Böbrek havuzcuğu (pelvis)."},{"q":"Böbreğin öz bölgesinde bulunan koni biçimli yapılara ne ad verilir?","steps":[{"t":"Öz bölgesinin yapısı","a":"Koni biçimli birimler","d":"Böbreğin öz bölgesi düzgün olmayıp koni biçimli bölümler içerir. Bu bölümler idrar toplama kanallarını barındırır. Uçları havuzcuğa doğru bakar."},{"t":"Yapının adı","a":"Böbrek piramitleri","d":"Öz bölgesindeki koni biçimli yapılara böbrek piramitleri denir. Piramitlerin uç kısımlarından idrar havuzcuğa damlar. Her piramit birçok toplama kanalı içerir."}],"ans":"Böbrek piramitleri."},{"q":"Böbreğe temiz (atıklı) kanı getiren damar hangisidir?","steps":[{"t":"Kan girişi","a":"Süzülecek kan gelir","d":"Böbreklerin süzme yapabilmesi için kanın böbreğe getirilmesi gerekir. Bu kan atıkları ve fazla suyu içerir. Kanın girişi büyük bir damarla olur."},{"t":"Damarın adı","a":"Böbrek atardamarı","d":"Böbreğe kanı getiren damar böbrek atardamarıdır (renal arter). Bu damar aorttan ayrılır ve içinde süzülecek kan vardır. Süzme sonrası temizlenen kan ayrı bir damarla çıkar."}],"ans":"Böbrek atardamarı (renal arter)."},{"q":"Süzülmüş (temizlenmiş) kanı böbrekten çıkaran damar hangisidir?","steps":[{"t":"Kan çıkışı","a":"Temizlenmiş kan ayrılır","d":"Böbrekte süzülen kandan atıklar ayrıldıktan sonra kan temizlenmiş olur. Bu kanın dolaşıma geri dönmesi gerekir. Çıkış da bir damarla sağlanır."},{"t":"Damarın adı","a":"Böbrek toplardamarı","d":"Temizlenmiş kanı böbrekten çıkaran damar böbrek toplardamarıdır (renal ven). Bu kan alt ana toplardamara verilir. Böylece arınmış kan dolaşıma geri katılır."}],"ans":"Böbrek toplardamarı (renal ven)."},{"q":"Böbrekteki nefronların süzme birimleri (Malpighi cisimcikleri) hangi bölgede yoğunlaşır?","steps":[{"t":"Süzme yapısının yeri","a":"Süzme nerede olur","d":"Nefronların kanı süzdüğü yapılar belirli bir bölgede yoğunlaşır. Bu bölge böbreğin dış katmanıdır. Süzme burada başlar."},{"t":"Bölge","a":"Kabuk (korteks)","d":"Malpighi cisimcikleri böbreğin kabuk (korteks) bölgesinde yoğun olarak bulunur. Bu nedenle süzme işlemi büyük ölçüde kabukta gerçekleşir. Henle kulpları ise öze doğru iner."}],"ans":"Kabuk (korteks) bölgesinde."},{"q":"Böbreğin iç kenarındaki, damarların ve üreterin bağlandığı girintili bölgeye ne ad verilir?","steps":[{"t":"Girintili bölge","a":"Damar ve kanal girişi","d":"Böbreğin içe çökük kenarında bir girinti bulunur. Buradan böbrek damarları girip çıkar ve üreter ayrılır. Bu bölge bağlantı noktasıdır."},{"t":"Bölgenin adı","a":"Böbrek kapısı (hilus)","d":"Bu girintili bölgeye böbrek kapısı (hilus) denir. Böbrek atardamarı, toplardamarı ve üreter bu kapıdan geçer. Böylece kan ve idrar yolları böbreğe burada bağlanır."}],"ans":"Böbrek kapısı (hilus)."},{"q":"Böbreklerin vücutta yaklaşık konumu neresidir?","steps":[{"t":"Genel konum","a":"Karın arka bölümü","d":"Böbrekler karın boşluğunun arka duvarında, omurganın iki yanında yer alır. Karın ön organlarının arkasında bulunurlar. Konumları korunaklıdır."},{"t":"Konumun belirlenmesi","a":"Bel bölgesi, omurga yanları","d":"Böbrekler bel hizasında, omurganın sağ ve sol tarafında simetrik olarak konumlanır. Sağ böbrek karaciğer nedeniyle biraz daha aşağıdadır. Alt kaburgalar tarafından korunurlar."}],"ans":"Bel bölgesinde, omurganın iki yanında."},{"q":"Böbreğin kabuk bölgesinin öz bölgesine göre rengi nasıldır?","steps":[{"t":"Bölgelerin görünümü","a":"İki farklı renk","d":"Böbrek kesildiğinde kabuk ve öz bölgeleri farklı renklerde görünür. Bu fark içyapılarının farklılığından kaynaklanır. Kabukta süzme yapıları yoğundur."},{"t":"Renk karşılaştırması","a":"Kabuk daha açık","d":"Kabuk (korteks) bölgesi öz (medulla) bölgesine göre daha açık renklidir. Öz bölgesi piramitler nedeniyle çizgili ve daha koyu görünür. Bu görünüm iki bölgeyi ayırt etmeyi sağlar."}],"ans":"Kabuk daha açık renklidir."},{"q":"Böbrek piramitlerinin uç kısımları hangi yapıya doğru yönelir?","steps":[{"t":"Piramidin yönelimi","a":"Uçların yönü","d":"Böbrek piramitleri koni biçimlidir ve tabanı kabuğa, ucu içe bakar. İdrar piramitlerin ucundan akar. Bu uçların yöneldiği yer önemlidir."},{"t":"Yönelim yeri","a":"Böbrek havuzcuğu","d":"Piramitlerin uçları böbrek havuzcuğuna (pelvis) doğru yönelir. İdrar bu uçlardan havuzcuğa damlar. Buradan üretere geçerek mesaneye iletilir."}],"ans":"Böbrek havuzcuğuna (pelvise)."},{"q":"Böbrek atardamarı hangi büyük damardan ayrılır?","steps":[{"t":"Kan kaynağı","a":"Vücudun ana atardamarı","d":"Böbreğe gelen kan vücudun en büyük atardamarından beslenir. Bu damar kalpten çıkan temiz kanı taşır. Böbrek için bir kol ayrılır."},{"t":"Damarın belirlenmesi","a":"Aort","d":"Böbrek atardamarı, vücudun ana atardamarı olan aorttan ayrılır. Bu sayede böbreğe yüksek basınçlı, atık yüklü kan ulaşır. Yüksek basınç süzme için önemlidir."}],"ans":"Aorttan."},{"q":"Böbreğin süzme ve geri emilim işini yapan mikroskobik birimine ne ad verilir?","steps":[{"t":"İşlevsel birim","a":"Böbreğin temel birimi","d":"Böbrek, çok sayıda küçük işlevsel birimden oluşur. Her birim süzme ve geri emilim yapabilir. Bu birimler mikroskobik düzeydedir."},{"t":"Birimin adı","a":"Nefron","d":"Böbreğin yapısal ve işlevsel birimine nefron denir. Her böbrekte milyonlarca nefron bulunur. İdrar bu nefronlarda oluşur."}],"ans":"Nefron."},{"q":"Böbreği dış etkilerden koruyan ve onu saran yağ tabakası ne işe yarar?","steps":[{"t":"Böbreğin çevresi","a":"Koruyucu kuşatma","d":"Böbrekler karın arka duvarında yağ ve bağ dokusuyla çevrilidir. Bu kuşatma böbreği yerinde tutar. Aynı zamanda dış etkilere karşı bir tampon oluşturur."},{"t":"Yağ tabakasının işlevi","a":"Koruma ve sabitleme","d":"Çevredeki yağ tabakası böbreği darbelere karşı yastıklayarak korur. Ayrıca böbreğin yerinden oynamasını engeller. Böylece böbrek hem korunur hem sabit kalır."}],"ans":"Böbreği korur ve yerinde sabitler."}],"zor":[{"q":"Böbrek atardamarındaki kan ile böbrek toplardamarındaki kanın atık içeriği bakımından farkı nedir, neden?","steps":[{"t":"Atardamar kanı","a":"Atık yüklü kan","d":"Böbrek atardamarı, süzülmeden önceki kanı böbreğe getirir. Bu kanda üre ve fazla su yüksek düzeydedir. Süzme henüz yapılmamıştır."},{"t":"Süzme süreci","a":"Atıklar ayrılır","d":"Kan böbrekte nefronlardan geçerken atıkları ve fazla suyu idrara verir. Böylece kandan atıklar uzaklaşır. Süzme sonrası kan temizlenir."},{"t":"Toplardamar kanı","a":"Temizlenmiş kan","d":"Böbrek toplardamarındaki kan atıklardan büyük ölçüde arınmıştır. Bu yüzden iki damar arasında atık farkı oluşur. Bu fark böbreğin süzme işlevinin doğrudan kanıtıdır."}],"ans":"Toplardamar kanı atık (üre) bakımından daha azdır; çünkü kan böbrekte süzülerek temizlenir."},{"q":"Bir böbrek alınan kişinin yaşamını sürdürebilmesi böbreğin hangi yapısal özelliğiyle açıklanır?","steps":[{"t":"Çift organ yapısı","a":"İki ayrı böbrek","d":"İnsanda iki ayrı böbrek bulunur ve her biri tek başına süzme yapabilir. Bu çift yapı yedeklilik sağlar. Biri çıkarılsa bile diğeri çalışabilir."},{"t":"Yedek kapasite","a":"Tek böbrek yeter","d":"Tek bir böbrek, gereken süzme işinin önemli kısmını üstlenebilir. Kalan böbrek görev fazlasını yüklenir ve büyüyebilir. Böylece atık atımı sürdürülür."},{"t":"Sonuç","a":"Tek böbrekle yaşam mümkün","d":"Böbreğin çift olması ve yüksek yedek kapasitesi sayesinde tek böbrekle yaşam sürdürülebilir. Bu, böbrek bağışını da mümkün kılar. Yine de tek böbreğin korunması önemlidir."}],"ans":"Böbreklerin çift olması ve tek böbreğin görevi sürdürebilecek yedek kapasitesi."},{"q":"Böbrek kabuk bölgesinde süzme yapılarının, öz bölgesinde ise kanalların yoğunlaşması işlevsel olarak ne anlama gelir?","steps":[{"t":"Kabuğun rolü","a":"Süzme bölgesi","d":"Kabukta Malpighi cisimcikleri yoğun olduğundan kanın süzülmesi büyük ölçüde burada başlar. Süzüntü burada oluşur. Bu nedenle kabuk süzme merkezi gibidir."},{"t":"Özün rolü","a":"Yoğunlaştırma bölgesi","d":"Öz bölgesinde Henle kulpları ve toplama kanalları bulunur. Burada su geri emilerek idrar yoğunlaştırılır. İdrar piramitler boyunca havuzcuğa iner."},{"t":"İşlevsel sonuç","a":"Bölgesel iş bölümü","d":"Kabuk süzmeyi, öz ise geri emilim ve yoğunlaştırmayı üstlenir. Bu bölgesel iş bölümü idrarın aşamalı olarak oluşmasını sağlar. Böylece yapı ile işlev uyum içindedir."}],"ans":"Kabukta süzme başlar, özde su geri emilip idrar yoğunlaşır; bölgesel iş bölümü vardır."},{"q":"Böbrek havuzcuğunda taş oluşması idrar akışını nasıl etkiler?","steps":[{"t":"Havuzcuğun görevi","a":"İdrar toplama-geçiş","d":"Böbrek havuzcuğu, piramitlerden gelen idrarı toplayıp üretere ileten boşluktur. Bu boşluk idrarın geçiş noktasıdır. Akışın düzenli olması gerekir."},{"t":"Taşın etkisi","a":"Geçişi tıkar","d":"Havuzcukta oluşan bir taş üreter ağzını ya da geçiş yolunu tıkayabilir. Bu durumda idrar ileri akamaz. Akış kısmen veya tamamen engellenir."},{"t":"Sonuç","a":"İdrar birikir, basınç artar","d":"Tıkanma nedeniyle idrar havuzcukta birikir ve geri basınç oluşturur. Bu basınç böbrek dokusuna zarar verebilir. Ayrıca şiddetli ağrıya yol açar."}],"ans":"İdrar akışını engeller; idrar birikip basınç ve hasar oluşturur."},{"q":"Böbrek atardamarı tıkanırsa o böbreğin süzme işlevinin durması nasıl açıklanır?","steps":[{"t":"Kan girişinin önemi","a":"Süzülecek kan gerekir","d":"Böbreğin süzme yapabilmesi için kanın böbreğe ulaşması zorunludur. Bu kanı böbrek atardamarı getirir. Kan olmadan süzme olamaz."},{"t":"Tıkanmanın etkisi","a":"Kan gelmez","d":"Atardamar tıkanırsa böbreğe yeterli kan ulaşamaz. Süzülecek kan olmadığı için nefronlar çalışamaz. Ayrıca doku oksijensiz kalır."},{"t":"Sonuç","a":"Süzme durur, doku zarar görür","d":"Kan akışı kesilince hem süzme durur hem de böbrek dokusu beslenemez. Uzarsa doku ölümü gelişebilir. Bu yüzden kan akışı böbrek için hayatidir."}],"ans":"Böbreğe kan gelmez, süzme durur ve doku oksijensiz kalıp zarar görür."},{"q":"Böbreğin fasulye biçiminde olması ile damar ve üreterin tek bir bölgeden girip çıkması arasında nasıl bir ilişki vardır?","steps":[{"t":"Fasulye biçimi","a":"İçe çökük kenar","d":"Böbreğin fasulye biçiminde olmasının nedeni iç kenarındaki çukurluktur. Bu çukur bölge böbrek kapısıdır. Buraya yapılar bağlanır."},{"t":"Tek noktadan bağlantı","a":"Hilustan giriş-çıkış","d":"Böbrek atardamarı, toplardamarı ve üreter bu girintili kapıdan geçer. Tek bir noktadan bağlantı düzenli ve korunaklı bir giriş sağlar. Bu yapı işlevi kolaylaştırır."},{"t":"Sonuç","a":"Biçim ile bağlantı uyumlu","d":"Böbreğin girintili (fasulye) biçimi, damar ve üreterin tek noktadan girip çıkmasını sağlar. Böylece bağlantılar düzenli kalır. Yapı ve işlev birbirini tamamlar."}],"ans":"Girintili (fasulye) biçim, damar ve üreterin tek noktadan (hilustan) bağlanmasını sağlar."},{"q":"Böbreğe gelen kanın yüksek basınçlı olmasının böbrek atardamarının aortla bağlantısıyla ilişkisi nedir?","steps":[{"t":"Aortun özelliği","a":"Yüksek basınçlı kan","d":"Aort, kalbin doğrudan pompaladığı kanı taşıyan en büyük atardamardır. İçindeki kan yüksek basınçlıdır. Bu basınç dallara da aktarılır."},{"t":"Böbrek atardamarı","a":"Aorttan kısa yol","d":"Böbrek atardamarı aorttan kısa bir kolla ayrılır. Bu nedenle böbreğe ulaşan kan basıncı yüksek kalır. Basınç fazla düşmeden böbreğe varır."},{"t":"İşlevsel sonuç","a":"Süzme için gerekli basınç","d":"Böbreğe yüksek basınçlı kanın gelmesi, glomerulusta süzülme için gereklidir. Aort bağlantısı bu basıncı sağlar. Böylece süzme verimli biçimde gerçekleşir."}],"ans":"Aorttan kısa yolla ayrıldığı için kan yüksek basınçlı kalır, bu da süzme için gereklidir."},{"q":"Böbrek dokusunun bol kan damarı içermesi onun işleviyle nasıl ilişkilendirilir?","steps":[{"t":"Böbreğin işi","a":"Kanı süzmek","d":"Böbreğin temel görevi kandaki atıkları süzmektir. Bu iş için bol miktarda kanın böbrekten geçmesi gerekir. Çok kan, çok süzme demektir."},{"t":"Damar bolluğu","a":"Yoğun kanlanma","d":"Böbrekler vücutta en çok kanlanan organlardandır. Kalpten çıkan kanın önemli bir bölümü böbreklerden geçer. Bu sayede kan kısa sürede defalarca süzülür."},{"t":"Sonuç","a":"Bol damar süzmeyi destekler","d":"Yoğun damar ağı, kanın hızlı ve sürekli süzülmesini sağlar. Böylece atıklar etkili biçimde uzaklaştırılır. Damar bolluğu doğrudan süzme işleviyle ilişkilidir."}],"ans":"Bol kan akışı kanın sürekli ve etkili süzülmesini sağlar."},{"q":"Böbrek öz bölgesindeki piramitlerin çizgili görünmesi hangi yapılardan kaynaklanır?","steps":[{"t":"Özün içeriği","a":"Paralel kanallar","d":"Böbrek özünde idrarı taşıyan toplama kanalları ve Henle kulpları bulunur. Bu yapılar piramitler boyunca aşağıya doğru uzanır. Birbirine paralel düzenlenmişlerdir."},{"t":"Çizgili görünüm","a":"Paralel borular","d":"Bu paralel uzanan kanallar piramitlere çizgili bir görünüm verir. Çizgiler kanalların yönünü gösterir. İdrar bu kanallar boyunca havuzcuğa iner."},{"t":"Sonuç","a":"Kanallar çizgi oluşturur","d":"Piramitlerdeki çizgili desen, paralel uzanan toplama kanalları ve Henle kulplarından kaynaklanır. Bu düzen idrarın yoğunlaştırılmasına yardımcı olur. Yapı görünümle uyumludur."}],"ans":"Paralel uzanan toplama kanalları ve Henle kulplarından."},{"q":"Böbrek kapısından geçen üç ana yapı hangileridir ve görevleri nedir?","steps":[{"t":"Kapıdan geçenler","a":"Üç yapı","d":"Böbrek kapısından (hilus) üç temel yapı geçer. Bunlardan ikisi kan damarı, biri idrar yoludur. Hepsi böbrek işlevi için gereklidir."},{"t":"Damarların görevi","a":"Kan giriş-çıkışı","d":"Böbrek atardamarı atık yüklü kanı içeri getirir, böbrek toplardamarı temizlenmiş kanı dışarı çıkarır. Bu iki damar kanın dolaşımını sağlar. Süzme bu kan akışına dayanır."},{"t":"Üreterin görevi","a":"İdrar çıkışı","d":"Üreter, böbrekte oluşan idrarı mesaneye taşır. Böylece atıklar vücuttan uzaklaştırılır. Üç yapı birlikte böbreğin işlevini tamamlar."}],"ans":"Böbrek atardamarı (kan getirir), böbrek toplardamarı (kan çıkarır), üreter (idrar çıkarır)."},{"q":"Böbreğin korteks ve medulla bölgelerinin farklı renkte görünmesi içyapılarıyla nasıl ilişkilidir?","steps":[{"t":"Korteksin içeriği","a":"Süzme cisimcikleri","d":"Korteks bölgesinde kanın süzüldüğü Malpighi cisimcikleri yoğundur. Bu yapılar bol kılcal damar içerir. Bu da bölgeye belirli bir görünüm verir."},{"t":"Medullanın içeriği","a":"Paralel kanallar","d":"Medulla bölgesinde ise paralel uzanan kanallar (Henle kulpu ve toplama kanalları) baskındır. Bu kanallar bölgeyi çizgili ve daha koyu gösterir. İçyapı bölgeden bölgeye değişir."},{"t":"Sonuç","a":"İçyapı rengi belirler","d":"Korteksteki süzme cisimcikleri ile medulladaki paralel kanallar farklı doku düzeni oluşturur. Bu fark iki bölgenin farklı renkte görünmesine yol açar. Görünüm, işlevsel farklılığın yansımasıdır."}],"ans":"Korteksteki süzme cisimcikleri ile medulladaki paralel kanalların farklı doku yapısından."},{"q":"Sağ böbreğin sol böbreğe göre biraz daha aşağıda bulunmasının nedeni nedir?","steps":[{"t":"Böbreklerin konumu","a":"Karın arka duvarı","d":"Böbrekler karın arka duvarında, omurganın iki yanında yer alır. Konumları çevredeki organlardan etkilenir. İki böbrek tam aynı hizada değildir."},{"t":"Karaciğerin etkisi","a":"Sağ üstte büyük organ","d":"Sağ üst karın boşluğunu büyük bir organ olan karaciğer doldurur. Karaciğer sağ böbreği aşağıya doğru iter. Bu nedenle sağ böbrek biraz daha alttadır."},{"t":"Sonuç","a":"Sağ böbrek daha aşağıda","d":"Karaciğerin sağ tarafta yer kaplaması sağ böbreğin konumunu aşağıya kaydırır. Sol tarafta böyle büyük bir baskı yoktur. Bu, normal anatomik bir durumdur."}],"ans":"Sağ üstteki büyük karaciğer sağ böbreği aşağıya iter."},{"q":"Böbreğin alt kaburgalar tarafından kısmen korunması işlevsel olarak neden önemlidir?","steps":[{"t":"Böbreğin konumu","a":"Karın arka üst bölge","d":"Böbrekler bel hizasında, vücudun arka tarafında yer alır. Bu konum onları bazı dış etkilere açık bırakabilir. Bu nedenle korunmaya gereksinim duyarlar."},{"t":"Kaburga koruması","a":"Kemiksel kalkan","d":"Alt kaburgalar böbreklerin üst kısmını kısmen örter. Kaburgalar sert kemik yapısıyla darbelere karşı kalkan görevi görür. Böylece böbrek dokusu korunur."},{"t":"İşlevsel önem","a":"Hassas organın korunması","d":"Böbrek, bol damarlı ve hassas bir organ olduğundan zedelenmeye karşı korunmalıdır. Kaburga koruması süzme işlevinin sürekliliğini güvence altına alır. Böylece organ darbelere karşı güvendedir."}],"ans":"Hassas ve bol damarlı böbreği darbelerden koruyup süzme işlevini güvenceye alır."},{"q":"Bir böbrek hasar gördüğünde diğer böbreğin büyümesi (hipertrofi) ne anlama gelir?","steps":[{"t":"Çift böbrek işlevi","a":"Görev paylaşımı","d":"Normalde iki böbrek süzme işini paylaşır. Biri hasar görürse paylaşım bozulur. Sağlam böbreğe daha çok iş düşer."},{"t":"Büyüme tepkisi","a":"Sağlam böbrek büyür","d":"Sağlam böbrek artan iş yükünü karşılamak için büyür ve daha çok kan süzer. Bu büyüme telafi amaçlıdır. Böbreğin uyum yeteneğini gösterir."},{"t":"Sonuç","a":"Telafi edici büyüme","d":"Diğer böbreğin büyümesi, kaybolan süzme kapasitesini kapatmaya yöneliktir. Bu sayede atık atımı sürdürülür. Bu olay böbreğin yedek kapasitesinin bir göstergesidir."}],"ans":"Sağlam böbreğin artan iş yükünü karşılamak için büyüyüp süzme kapasitesini telafi etmesi."},{"q":"Böbrek dokusunun oksijene çok bağımlı olması kanlanmasıyla nasıl ilişkilendirilir?","steps":[{"t":"Böbreğin etkinliği","a":"Yoğun çalışma","d":"Böbrekler sürekli süzme ve geri emilim yapar. Özellikle geri emilim aktif taşıma gerektirir ve enerji harcar. Enerji üretimi oksijen gerektirir."},{"t":"Oksijen gereksinimi","a":"Bol oksijen ister","d":"Aktif taşıma için bol enerji, enerji için de bol oksijen gerekir. Bu yüzden böbrek dokusu oksijene çok bağımlıdır. Oksijen kanla taşınır."},{"t":"Sonuç","a":"Bol kanlanma oksijen sağlar","d":"Böbreğin yoğun kanlanması, hem süzülecek kanı hem de oksijeni sağlar. Kan akışı kesilirse böbrek hızla zarar görür. Bu nedenle kanlanma hem süzme hem oksijen için kritiktir."}],"ans":"Aktif taşımanın enerji ve oksijen gereksinimi, böbreğin bol kanlanmasıyla karşılanır."}]}},"nefron":{"lise":{"kolay":[{"q":"Böbreğin yapısal ve işlevsel birimine ne ad verilir?","steps":[{"t":"İşlevsel birim kavramı","a":"En küçük çalışan birim","d":"Böbrek, kendi başına süzme ve geri emilim yapabilen çok sayıda küçük birimden oluşur. Bu birimler böbreğin işini gerçekleştirir. Mikroskobik boyuttadırlar."},{"t":"Birimin adı","a":"Nefron","d":"Böbreğin yapısal ve işlevsel birimi nefrondur. Her böbrekte milyonlarca nefron bulunur. İdrar oluşumu bu birimlerde gerçekleşir."}],"ans":"Nefron."},{"q":"Nefronun süzme görevi yapan, kılcal yumak biçimindeki yapısı hangisidir?","steps":[{"t":"Süzme noktası","a":"Kılcal yumak","d":"Nefronda kanın süzüldüğü yer, sıkıca sarılı kılcal damarlardan oluşur. Bu yumak biçimli yapıya kan getirilir. Süzme burada başlar."},{"t":"Yapının adı","a":"Glomerulus","d":"Bu kılcal damar yumağına glomerulus denir. Glomerulustaki yüksek basınç sayesinde kan süzülür. Süzüntü buradan Bowman kapsülüne geçer."}],"ans":"Glomerulus."},{"q":"Glomerulusu çevreleyen ve süzüntüyü toplayan çift duvarlı yapı hangisidir?","steps":[{"t":"Süzüntünün toplandığı yer","a":"Glomerulusu saran kap","d":"Glomerulusta süzülen sıvının bir yere toplanması gerekir. Bu sıvıyı toplayan yapı glomerulusu sarar. Fincan biçimlidir."},{"t":"Yapının adı","a":"Bowman kapsülü","d":"Glomerulusu çevreleyen çift duvarlı, fincan biçimli yapıya Bowman kapsülü denir. Süzülen sıvı bu kapsülün içine dolar. Buradan tübüllere geçer."}],"ans":"Bowman kapsülü."},{"q":"Glomerulus ile Bowman kapsülünün birlikte oluşturduğu yapıya ne ad verilir?","steps":[{"t":"İki yapının birleşimi","a":"Süzme cisimciği","d":"Glomerulus ve onu saran Bowman kapsülü bir arada süzme görevi yapar. Bu ikili birlikte tek bir yapı olarak ele alınır. Süzme bu birimde gerçekleşir."},{"t":"Birimin adı","a":"Malpighi cisimciği","d":"Glomerulus ile Bowman kapsülünün oluşturduğu yapıya Malpighi cisimciği (böbrek cisimciği) denir. Bu cisimcik böbreğin kabuk bölgesinde bulunur. Kanın süzülmesi burada başlar."}],"ans":"Malpighi cisimciği (böbrek cisimciği)."},{"q":"Bowman kapsülünden sonra gelen, geri emilimin yoğun olduğu ilk tübül hangisidir?","steps":[{"t":"Kapsülden sonrası","a":"İlk tübül bölümü","d":"Süzüntü Bowman kapsülünden çıktıktan sonra kıvrımlı bir kanala geçer. Bu kanal nefronun ilk tübül bölümüdür. Geri emilim burada yoğundur."},{"t":"Tübülün adı","a":"Proksimal tübül","d":"Bowman kapsülünden sonra gelen kıvrımlı kanala proksimal tübül denir. Burada glikoz, aminoasit, su ve iyonların büyük kısmı geri emilir. Bu nedenle geri emilimin en yoğun olduğu bölümdür."}],"ans":"Proksimal tübül."},{"q":"Nefronda öz bölgesine inip geri dönen U biçimli yapı hangisidir?","steps":[{"t":"U biçimli yapı","a":"İnen ve çıkan kol","d":"Proksimal tübülden sonra kanal öz bölgesine doğru iner, sonra geri döner. Bu iniş-çıkış U biçimli bir yapı oluşturur. Su ve tuz dengesinde rol oynar."},{"t":"Yapının adı","a":"Henle kulpu","d":"Bu U biçimli yapıya Henle kulpu denir. İnen kolda su, çıkan kolda tuz hareketleri olur. Henle kulpu idrarın yoğunlaştırılmasına katkıda bulunur."}],"ans":"Henle kulpu."},{"q":"Henle kulpundan sonra gelen tübül hangisidir?","steps":[{"t":"Kulptan sonrası","a":"Sonraki tübül","d":"Henle kulpu öze inip geri döndükten sonra süzüntü bir tübüle daha geçer. Bu tübül kabuk bölgesine geri ulaşır. Burada da bazı madde alışverişleri olur."},{"t":"Tübülün adı","a":"Distal tübül","d":"Henle kulpundan sonra gelen kıvrımlı kanala distal tübül denir. Burada iyon ve su ayarı sürer. Distal tübül daha sonra toplama kanalına bağlanır."}],"ans":"Distal tübül."},{"q":"Birçok nefrondan gelen idrarı toplayıp havuzcuğa ileten yapı hangisidir?","steps":[{"t":"Ortak toplama","a":"Nefronların ortak kanalı","d":"Çok sayıda nefron, ürettiği idrarı ortak bir kanala boşaltır. Bu kanal idrarı bir araya toplar. Tek tek nefronların ürünü burada birleşir."},{"t":"Yapının adı","a":"Toplama kanalı","d":"Birçok nefrondan gelen idrarı toplayıp böbrek havuzcuğuna ileten yapıya toplama kanalı denir. Bu kanal öz bölgesindeki piramitlerden geçer. İdrar buradan havuzcuğa damlar."}],"ans":"Toplama kanalı."},{"q":"Glomerulusa kan getiren atardamar kolu hangisidir?","steps":[{"t":"Kan girişi","a":"Glomerulusa kan","d":"Glomerulusun süzme yapabilmesi için içine kan getirilmelidir. Bu kanı bir atardamar kolu sağlar. Kol glomerulusa girer."},{"t":"Damarın adı","a":"Getirici arteriol","d":"Glomerulusa kan getiren atardamar koluna getirici arteriol denir. Bu damar geniş olduğundan glomerulusa bol kan ulaşır. Süzme için gereken basıncı sağlar."}],"ans":"Getirici arteriol (afferent arteriol)."},{"q":"Glomerulustan kanı çıkaran ve getiriciden daha dar olan damar hangisidir?","steps":[{"t":"Kan çıkışı","a":"Glomerulustan çıkan damar","d":"Glomerulusa giren kan, süzüldükten sonra başka bir damarla çıkar. Bu çıkış damarı getirici damardan farklıdır. Daha dardır."},{"t":"Damarın adı","a":"Götürücü arteriol","d":"Glomerulustan kanı çıkaran damar götürücü arterioldür. Götürücü arteriol getiriciden daha dar olduğundan glomerulus içinde basınç yükselir. Bu basınç süzmeyi kolaylaştırır."}],"ans":"Götürücü arteriol (efferent arteriol)."},{"q":"Nefronların Malpighi cisimcikleri böbreğin hangi bölgesinde bulunur?","steps":[{"t":"Cisimciğin yeri","a":"Süzmenin yapıldığı yer","d":"Malpighi cisimcikleri kanın süzüldüğü yapılardır. Bu yapılar böbreğin belirli bir bölgesinde toplanır. Süzme orada başlar."},{"t":"Bölge","a":"Kabuk (korteks)","d":"Malpighi cisimcikleri böbreğin kabuk (korteks) bölgesinde bulunur. Henle kulpları ise öze doğru iner. Bu yerleşim süzme ve yoğunlaştırma işlerini ayırır."}],"ans":"Kabuk (korteks) bölgesinde."},{"q":"Nefronda idrarın izlediği yolun başlangıç yapısı hangisidir?","steps":[{"t":"Akışın başlangıcı","a":"Süzüntü nerede oluşur","d":"İdrarın ham hali olan süzüntü, kanın süzüldüğü yapıda oluşur. Bu yapı nefronun başlangıcıdır. Akış buradan başlar."},{"t":"Başlangıç yapısı","a":"Bowman kapsülü","d":"Glomerulusta süzülen sıvı önce Bowman kapsülüne dolar. Yani nefronda idrar yolculuğu Bowman kapsülünden başlar. Buradan proksimal tübüle geçer."}],"ans":"Bowman kapsülü."},{"q":"Nefronda süzüntünün izlediği doğru sıra nedir?","steps":[{"t":"Yapıların sırası","a":"Süzme sonrası yol","d":"Süzüntü Bowman kapsülünden başlayıp tübüller boyunca ilerler. Her bölüm sırayla geçilir. En sonda toplama kanalına ulaşır."},{"t":"Sıranın yazılması","a":"Bowman→proksimal→Henle→distal→toplama","d":"Süzüntü sırasıyla Bowman kapsülü, proksimal tübül, Henle kulpu, distal tübül ve toplama kanalını izler. Bu yol boyunca geri emilim ve salgılama olur. Sonunda idrar havuzcuğa ulaşır."}],"ans":"Bowman kapsülü → proksimal tübül → Henle kulpu → distal tübül → toplama kanalı."},{"q":"Bir böbrekte yaklaşık kaç nefron bulunur?","steps":[{"t":"Nefron sayısı kavramı","a":"Çok sayıda birim","d":"Böbreğin süzme kapasitesi çok yüksektir. Bu kapasite çok sayıda nefronla sağlanır. Nefronlar mikroskobik olduğundan bir böbreğe milyonlarcası sığar."},{"t":"Sayının belirlenmesi","a":"Yaklaşık 1 milyon","d":"Bir böbrekte yaklaşık bir milyon nefron bulunur. Bu kadar çok birim, kanın etkin biçimde süzülmesini sağlar. İki böbrekte toplam sayı çok daha yüksektir."}],"ans":"Yaklaşık 1 milyon nefron."},{"q":"Nefronda süzme görevini glomerulus, geri emilim görevini ise ağırlıklı olarak hangi bölüm yapar?","steps":[{"t":"Süzme bölümü","a":"Glomerulus süzer","d":"Glomerulusta kan basıncı etkisiyle süzme gerçekleşir. Süzüntü Bowman kapsülüne geçer. Bu aşamada henüz geri emilim olmaz."},{"t":"Geri emilim bölümü","a":"Proksimal tübül emer","d":"Süzüntüdeki yararlı maddeler büyük ölçüde proksimal tübülde geri emilir. Burada glikoz, aminoasit, su ve iyonlar kana döner. Bu nedenle geri emilim en çok proksimal tübülde olur."}],"ans":"Süzmeyi glomerulus, geri emilimi ağırlıklı olarak proksimal tübül yapar."}],"zor":[{"q":"Götürücü arteriolün getirici arteriolden daha dar olmasının glomerulustaki süzmeye etkisi nedir?","steps":[{"t":"Damar genişlikleri","a":"Giriş geniş, çıkış dar","d":"Glomerulusa kanı getirici arteriol getirir ve bu damar geniştir. Kanı çıkaran götürücü arteriol ise daha dardır. Giriş ile çıkış arasında genişlik farkı vardır."},{"t":"Basınç oluşumu","a":"Kan glomerulusta sıkışır","d":"Kanın geniş bir damardan girip dar bir damardan çıkması glomerulus içinde sıkışmaya yol açar. Bu sıkışma kan basıncını yükseltir. Yüksek basınç süzmeyi zorlar."},{"t":"Sonuç","a":"Süzme kolaylaşır","d":"Glomerulustaki yüksek basınç, sıvının kılcal duvarından Bowman kapsülüne süzülmesini sağlar. Götürücü arteriolün darlığı bu basıncı korur. Böylece süzme verimli biçimde gerçekleşir."}],"ans":"Çıkışın dar olması glomerulus içi basıncı yükseltir, bu da süzmeyi kolaylaştırır."},{"q":"Proksimal tübülün geri emilim yapan epitel hücrelerinde mitokondri ve mikrovillus (çıkıntı) çok olması neyi gösterir?","steps":[{"t":"Mitokondrinin işlevi","a":"Enerji üretimi","d":"Mitokondri hücrede enerji (ATP) üreten organeldir. Bol mitokondri, hücrenin çok enerji harcadığını gösterir. Proksimal tübülde geri emilim aktif taşımayla yapılır."},{"t":"Mikrovillusun işlevi","a":"Yüzey artışı","d":"Mikrovilluslar hücre yüzeyini genişleten parmaksı çıkıntılardır. Bol mikrovillus emilim yüzeyini büyütür. Böylece daha çok madde emilebilir."},{"t":"Sonuç","a":"Yoğun aktif geri emilim","d":"Bol mitokondri enerji, bol mikrovillus geniş yüzey sağlar; ikisi birlikte yoğun aktif geri emilime işaret eder. Bu yüzden proksimal tübül geri emilimin en güçlü olduğu yerdir. Yapı ile işlev uyumludur."}],"ans":"Proksimal tübülde yoğun aktif geri emilim yapıldığını gösterir."},{"q":"Glomerulustaki süzme yapısı protein gibi büyük molekülleri neden geçirmez?","steps":[{"t":"Süzme engelinin yapısı","a":"Küçük gözenekli yapı","d":"Glomerulus kılcal duvarı ve Bowman kapsülü çeperi küçük gözenekli bir süzme engeli oluşturur. Bu engel küçük molekülleri geçirir. Gözenekler büyük molekülleri tutar."},{"t":"Protein boyutu","a":"Büyük moleküller","d":"Proteinler bu gözeneklerden geçemeyecek kadar büyük moleküllerdir. Bu yüzden süzme engelinden geçemezler. Su, glikoz, üre gibi küçük moleküller ise geçer."},{"t":"Sonuç","a":"Protein süzülmez","d":"Süzme yapısının seçici geçirgenliği proteinleri kanda tutar. Bu sayede yararlı büyük moleküller kaybedilmez. Sağlıklı idrarda protein bulunmaması bununla açıklanır."}],"ans":"Süzme yapısının gözenekleri küçük olduğundan büyük protein molekülleri geçemez."},{"q":"Bir nefronun getirici arteriolü daralırsa o nefronun süzme miktarında nasıl bir değişim beklenir?","steps":[{"t":"Getiricinin görevi","a":"Glomerulusa kan getirir","d":"Getirici arteriol glomerulusa kan ileterek süzme için gereken kan ve basıncı sağlar. Kan miktarı süzmeyi belirler. Bu damar süzmenin girdisidir."},{"t":"Daralmanın etkisi","a":"Az kan, düşük basınç","d":"Getirici arteriol daralırsa glomerulusa daha az kan ulaşır ve basınç düşer. Düşük basınç süzme gücünü azaltır. Daha az sıvı süzülür."},{"t":"Sonuç","a":"Süzme azalır","d":"Getiricinin daralmasıyla glomerulustaki süzme miktarı düşer. Bu, idrar oluşumunu da azaltır. Damar genişlikleri böbrek süzmesini doğrudan etkiler."}],"ans":"Glomerulusa az kan ve düşük basınç ulaşır, süzme miktarı azalır."},{"q":"Nefronun Malpighi cisimciğinin kabukta, Henle kulpunun ise öze inmesi işlevsel olarak nasıl açıklanır?","steps":[{"t":"Kabuktaki süzme","a":"Cisimcik kabukta","d":"Malpighi cisimciği kabukta yer alır ve süzme burada gerçekleşir. Kabuk süzme cisimciklerince zengindir. Süzüntü burada oluşmaya başlar."},{"t":"Özdeki yoğunlaştırma","a":"Kulp öze iner","d":"Henle kulpu öze doğru iner ve burada su-tuz hareketleriyle ortam derişimi ayarlanır. Bu, idrarın yoğunlaştırılmasını sağlar. Öz bölgesi tuz bakımından derişiktir."},{"t":"Sonuç","a":"Bölgesel iş bölümü","d":"Süzme kabukta, idrarın yoğunlaştırılması ise öze inen Henle kulpunda gerçekleşir. Bu yerleşim işlevsel bir iş bölümü oluşturur. Nefronun yapısı bu iş bölümünü destekler."}],"ans":"Süzme kabuktaki cisimcikte, idrarın yoğunlaştırılması öze inen Henle kulpunda olur."},{"q":"Glomerulusun bir kılcal damar yumağı olması süzme yüzeyi açısından ne avantaj sağlar?","steps":[{"t":"Yumak yapısı","a":"Sarmal kılcal damarlar","d":"Glomerulus, sıkıca sarılı çok sayıda kılcal damardan oluşan bir yumaktır. Bu yapı küçük bir alana çok damar sığdırır. Damar duvarları süzme yüzeyidir."},{"t":"Yüzey artışı","a":"Geniş süzme alanı","d":"Çok sayıda kılcal damar, toplam süzme yüzeyini büyütür. Geniş yüzeyden daha çok sıvı süzülebilir. Böylece süzme verimi artar."},{"t":"Sonuç","a":"Etkili süzme","d":"Yumak biçimi süzme yüzeyini en üst düzeye çıkarır ve etkili süzmeyi sağlar. Bu yapı, kısa sürede çok kanın süzülmesini mümkün kılar. Yapı doğrudan işlevle bağlantılıdır."}],"ans":"Yumak yapısı süzme yüzeyini artırarak etkili süzme sağlar."},{"q":"Süzüntü proksimal tübülden geçerken hacminin azalması neyle açıklanır?","steps":[{"t":"İlk süzüntü hacmi","a":"Çok miktarda sıvı","d":"Glomerulustan süzülen sıvı (ilk süzüntü) çok büyük hacimlidir. İçinde su, glikoz, iyon ve atıklar bulunur. Bu sıvı tübüllere geçer."},{"t":"Geri emilim","a":"Su ve madde geri alınır","d":"Proksimal tübülde su, glikoz, aminoasit ve iyonların büyük kısmı geri emilerek kana döner. Bu emilimle tübüldeki sıvı miktarı azalır. Yararlı maddeler kaybedilmez."},{"t":"Sonuç","a":"Süzüntü hacmi azalır","d":"Geri emilim nedeniyle proksimal tübül boyunca süzüntü hacmi belirgin biçimde düşer. Böylece atık daha yoğun, sıvı daha az olur. Bu, idrarın oluşum sürecinin önemli bir adımıdır."}],"ans":"Su ve yararlı maddelerin büyük kısmının geri emilmesiyle hacim azalır."},{"q":"Toplama kanalının birçok nefronun idrarını birleştirmesi böbrek yapısında nasıl bir düzen oluşturur?","steps":[{"t":"Nefron ürünleri","a":"Ayrı ayrı idrar","d":"Her nefron kendi süzme ve geri emilim işlemini yaparak idrar oluşturur. Milyonlarca nefron ayrı ayrı çalışır. Ürünlerinin birleştirilmesi gerekir."},{"t":"Birleştirme","a":"Ortak kanala dökülme","d":"Çok sayıda nefronun distal tübülü ortak bir toplama kanalına açılır. Böylece idrar bir araya gelir. Toplama kanalları piramitlerde paralel uzanır."},{"t":"Sonuç","a":"Dallanmış toplayıcı düzen","d":"Toplama kanalları, çok sayıda nefronu havuzcuğa bağlayan dallanmış bir düzen oluşturur. Bu düzen idrarı verimli biçimde toplar. Piramitlerin çizgili görünümü de bu kanallardan kaynaklanır."}],"ans":"Çok sayıda nefronu havuzcuğa bağlayan dallanmış toplayıcı bir düzen oluşturur."},{"q":"Glomerulusun iki arteriol (getirici ve götürücü) arasında bulunması dolaşımda nasıl bir özelliktir?","steps":[{"t":"Olağan kılcal ağ","a":"Atardamar-toplardamar arası","d":"Vücutta kılcal damarlar genellikle bir atardamar ile bir toplardamar arasında yer alır. Kan atardamardan kılcala, oradan toplardamara akar. Bu olağan düzendir."},{"t":"Glomerulusun farkı","a":"İki arteriol arası","d":"Glomerulus ise iki atardamar kolu (getirici ve götürücü arteriol) arasında bulunur. Yani kan kılcal yumağa bir arteriolden girer, başka bir arteriolden çıkar. Bu olağan dışı bir durumdur."},{"t":"Sonuç","a":"Basınç korunur","d":"İki arteriol arasında bulunma, glomerulusta yüksek basıncın korunmasını sağlar. Bu yüksek basınç süzme için gereklidir. Böylece glomerulus özel bir kılcal ağ olur."}],"ans":"Glomerulus iki arteriol arasında bulunur; bu, süzme için yüksek basıncı korur."},{"q":"Bir kişinin nefron sayısının yaşla birlikte azalması böbrek işlevini nasıl etkiler?","steps":[{"t":"Nefron ve süzme","a":"Süzme kapasitesi","d":"Böbreğin süzme gücü çalışan nefron sayısıyla orantılıdır. Çok nefron, yüksek süzme kapasitesi demektir. Nefronlar süzmenin temel birimidir."},{"t":"Azalmanın etkisi","a":"Süzme gücü düşer","d":"Yaşla birlikte bazı nefronlar işlevini yitirir ve toplam süzme kapasitesi azalır. Kalan nefronlar daha çok yüklenir. Süzme verimi yavaş yavaş düşer."},{"t":"Sonuç","a":"Böbrek işlevi zayıflar","d":"Nefron sayısının azalması böbreğin atık atma ve denge sağlama gücünü azaltır. Bu nedenle yaşlılıkta böbrek işlevi gerileyebilir. Yine de yedek kapasite uzun süre yeterli olabilir."}],"ans":"Süzme kapasitesi azalır, böbreğin atık atma gücü zayıflar."},{"q":"Distal tübül ile proksimal tübül arasında geri emilim yoğunluğu bakımından fark var mıdır?","steps":[{"t":"Proksimal tübül","a":"Yoğun geri emilim","d":"Proksimal tübül, süzüntüdeki glikoz, aminoasit, su ve iyonların büyük kısmını geri emer. Burada geri emilim en yüksektir. Yararlı maddelerin neredeyse tamamı burada alınır."},{"t":"Distal tübül","a":"Ayar amaçlı emilim","d":"Distal tübülde ise emilim daha çok ince ayar amaçlıdır. Burada özellikle iyon ve su dengesi düzenlenir. Geri emilim miktarı proksimaldekinden azdır."},{"t":"Sonuç","a":"Proksimalde daha yoğun","d":"Geri emilim proksimal tübülde yoğun ve genel, distal tübülde ise sınırlı ve ayar niteliğindedir. Bu iş bölümü idrarın bileşimini hassas biçimde belirler. İki tübül farklı işlevsel ağırlığa sahiptir."}],"ans":"Evet; proksimalde geri emilim çok yoğun, distalde ise sınırlı ve ayar amaçlıdır."},{"q":"Glomerulustaki süzme durduğunda nefronun geri kalan bölümlerinin işlevsiz kalması neden beklenir?","steps":[{"t":"Süzmenin önceliği","a":"İlk adım süzme","d":"Nefronda her işlem, glomerulusta süzülerek oluşan süzüntü üzerinde yapılır. Süzme nefronun ilk ve temel adımıdır. Diğer işlevler bu süzüntüye bağlıdır."},{"t":"Süzme durunca","a":"İşlenecek sıvı yok","d":"Glomerulusta süzme durursa tübüllere sıvı geçmez. Geri emilim ve salgılama için işlenecek süzüntü kalmaz. Böylece sonraki bölümler boşta kalır."},{"t":"Sonuç","a":"Nefron işlevsiz kalır","d":"Süzüntü oluşmadığında proksimal, Henle, distal ve toplama kanalı görevini yapamaz. Çünkü hepsi süzüntü üzerinde çalışır. Süzmenin durması tüm nefronu işlevsiz bırakır."}],"ans":"Süzüntü oluşmazsa tübüllerin işleyeceği sıvı kalmaz, geri emilim ve salgılama duraklar."},{"q":"Nefronun glomerulus çevresinde ikinci bir kılcal ağ (peritübüler kılcallar) bulunması geri emilimle nasıl ilişkilidir?","steps":[{"t":"İkinci kılcal ağ","a":"Tübül çevresinde damar","d":"Götürücü arteriol glomerulustan çıktıktan sonra tübüllerin çevresinde ikinci bir kılcal ağ oluşturur. Bu ağ tübüllerle yakın temas hâlindedir. Geri emilim için uygun konumdadır."},{"t":"Geri emilim hedefi","a":"Maddeleri kana almak","d":"Proksimal tübülde geri emilen su, glikoz ve iyonların kana geri dönmesi gerekir. Bu maddeler tübül çevresindeki kılcallara alınır. Böylece dolaşıma katılırlar."},{"t":"Sonuç","a":"Emilen madde kana döner","d":"Peritübüler kılcal ağ, geri emilen yararlı maddeleri toplayıp kana aktarır. Bu sayede süzme ile kaybedilen değerli maddeler geri kazanılır. İkinci kılcal ağ geri emilimin tamamlanmasını sağlar."}],"ans":"Tübüllerden geri emilen su ve maddeleri toplayıp kana geri taşır."},{"q":"Glomerulustaki kılcal damar duvarının ince ve gözenekli olması süzmeyi nasıl kolaylaştırır?","steps":[{"t":"Duvar yapısı","a":"İnce ve gözenekli","d":"Glomerulus kılcal damarlarının duvarı çok incedir ve küçük gözenekler içerir. Bu yapı sıvı ve küçük moleküllerin geçişine izin verir. Büyük molekülleri ise tutar."},{"t":"Geçiş kolaylığı","a":"Sıvı hızla süzülür","d":"İnce duvar geçiş mesafesini kısaltır, gözenekler ise küçük moleküllerin çıkışını sağlar. Yüksek basınçla birlikte sıvı hızla Bowman kapsülüne geçer. Süzme verimi yükselir."},{"t":"Sonuç","a":"Etkili ve seçici süzme","d":"İnce ve gözenekli duvar, hem hızlı hem seçici bir süzmeyi mümkün kılar. Su ve küçük atıklar geçerken proteinler kalır. Bu yapı süzme işlevine tam uyumludur."}],"ans":"İnce duvar geçişi kısaltır, gözenekler küçük molekülleri geçirir; süzme hızlanır ve seçici olur."},{"q":"Nefronun süzme, geri emilim ve salgılama olmak üzere üç temel işlevi olması idrar bileşimini nasıl belirler?","steps":[{"t":"Süzme","a":"Ham süzüntü oluşur","d":"Glomerulusta kandan su, iyon, glikoz ve atıklar süzülerek ham süzüntü oluşur. Bu süzüntü hem yararlı hem atık maddeleri içerir. İdrarın başlangıç hâlidir."},{"t":"Geri emilim ve salgılama","a":"Düzenleme yapılır","d":"Geri emilimle yararlı maddeler kana geri alınır; salgılamayla bazı fazla maddeler tübüle eklenir. Böylece süzüntünün bileşimi değiştirilir. İdrar adım adım biçimlenir."},{"t":"Sonuç","a":"Son idrar oluşur","d":"Süzme, geri emilim ve salgılamanın ortak etkisiyle idrarın son bileşimi belirlenir. Yararlı maddeler tutulur, atıklar atılır. Bu üç işlev birlikte iç dengeyi korur."}],"ans":"Süzme ham süzüntüyü, geri emilim ve salgılama ise son idrarın bileşimini belirler."}]}},"filtrasyon":{"lise":{"kolay":[{"q":"Böbrekte kanın süzülmesi (filtrasyon) hangi yapıda gerçekleşir?","steps":[{"t":"Süzme noktası","a":"Kılcal yumak","d":"Kanın süzülmesi nefronun süzme biriminde gerçekleşir. Bu birim kılcal bir damar yumağı içerir. Süzme burada başlar."},{"t":"Yapının adı","a":"Glomerulus","d":"Kanın süzülmesi glomerulusta gerçekleşir. Glomerulustaki yüksek basınç sayesinde sıvı kandan ayrılır. Süzüntü Bowman kapsülüne geçer."}],"ans":"Glomerulusta."},{"q":"Glomerulusta süzülmeyi sağlayan başlıca etken nedir?","steps":[{"t":"Süzmenin itici gücü","a":"Bir kuvvet gerekir","d":"Kandan sıvının damar duvarından dışarı çıkması için bir itici güç gereklidir. Bu güç kanın damar içinde uyguladığı basınçtır. Basınç süzmeyi yürütür."},{"t":"Etkenin belirlenmesi","a":"Yüksek kan basıncı","d":"Glomerulustaki yüksek kan basıncı, sıvıyı kandan Bowman kapsülüne doğru iter. Bu basınç süzmenin temel itici gücüdür. Basınç düşerse süzme azalır."}],"ans":"Glomerulustaki yüksek kan basıncı."},{"q":"Glomerulusta süzülen ilk sıvıya ne ad verilir?","steps":[{"t":"Süzme ürünü","a":"Ham sıvı","d":"Glomerulusta kandan süzülen sıvı henüz son idrar değildir. Bu sıvı geri emilim ve salgılama görmemiştir. Süzme aşamasının ilk ürünüdür."},{"t":"Ürünün adı","a":"Süzüntü (filtrat)","d":"Glomerulusta oluşan bu ham sıvıya süzüntü (filtrat) denir. İçinde su, iyon, glikoz ve atıklar bulunur. Tübüllerde işlenerek idrara dönüşür."}],"ans":"Süzüntü (filtrat)."},{"q":"İlk süzüntünün (filtratın) bileşimi kan plazmasına göre hangi maddeden yoksundur?","steps":[{"t":"Süzme seçiciliği","a":"Büyük molekül geçmez","d":"Glomerulustaki süzme yapısı yalnızca küçük molekülleri geçirir. Büyük moleküller geçemez. Bu nedenle süzüntü plazmadan farklılaşır."},{"t":"Yoksun olduğu madde","a":"Proteinler","d":"İlk süzüntü, plazmaya benzer ancak büyük protein moleküllerinden yoksundur. Çünkü proteinler süzme engelinden geçemez. Bu yüzden süzüntü proteinsiz plazma gibidir."}],"ans":"Büyük protein moleküllerinden."},{"q":"Glomerulustan kanı çıkaran götürücü arteriolün dar olması süzmeyi nasıl etkiler?","steps":[{"t":"Çıkış darlığı","a":"Kan zor çıkar","d":"Götürücü arteriol getiriciden daha dardır. Bu darlık kanın glomerulustan çıkışını zorlaştırır. Kan glomerulusta birikme eğilimi gösterir."},{"t":"Basınç etkisi","a":"Basınç artar, süzme artar","d":"Çıkışın dar olması glomerulus içi basıncı yükseltir. Yüksek basınç süzmeyi artırır. Böylece daha çok sıvı süzülür."}],"ans":"Glomerulus içi basıncı artırarak süzmeyi kolaylaştırır."},{"q":"Süzülen sıvı (süzüntü) glomerulustan hangi yapıya geçer?","steps":[{"t":"Süzme sonrası","a":"Toplanma yeri","d":"Glomerulusta süzülen sıvının bir yere toplanması gerekir. Bu sıvı glomerulusu saran yapıya dolar. Buradan tübüllere ilerler."},{"t":"Geçiş yeri","a":"Bowman kapsülü","d":"Süzüntü glomerulustan Bowman kapsülüne geçer. Bowman kapsülü süzüntüyü toplayıp proksimal tübüle iletir. Böylece idrar oluşumu süzme ile başlar."}],"ans":"Bowman kapsülüne."},{"q":"Glomerulusta su ve küçük moleküller süzülürken kan hücreleri neden süzülmez?","steps":[{"t":"Hücrelerin boyutu","a":"Büyük yapılar","d":"Alyuvar, akyuvar gibi kan hücreleri büyük yapılardır. Süzme engelindeki gözenekler ise küçüktür. Boyut farkı geçişi belirler."},{"t":"Süzme sonucu","a":"Hücreler kanda kalır","d":"Büyük olan kan hücreleri süzme engelinden geçemez ve kanda kalır. Su ve küçük moleküller ise süzülür. Bu yüzden sağlıklı süzüntüde kan hücresi bulunmaz."}],"ans":"Kan hücreleri büyük olduğundan süzme engelinden geçemez."},{"q":"Glomerulustaki süzme olayı seçici midir yoksa rastgele mi?","steps":[{"t":"Süzmenin doğası","a":"Boyuta göre geçiş","d":"Glomerulustaki süzme, moleküllerin boyutuna göre gerçekleşir. Küçük moleküller geçer, büyükler geçemez. Bu nedenle süzme rastgele değildir."},{"t":"Seçicilik","a":"Boyuta dayalı seçicilik","d":"Süzme, molekül büyüklüğüne dayalı bir seçicilik gösterir. Su, iyon, glikoz, üre geçerken protein ve hücreler geçmez. Bu yüzden süzme seçici bir olaydır."}],"ans":"Seçicidir (molekül büyüklüğüne göre)."},{"q":"İlk süzüntüde glikoz bulunur mu?","steps":[{"t":"Glikozun boyutu","a":"Küçük molekül","d":"Glikoz, suda çözünmüş küçük bir moleküldür. Süzme engelindeki gözeneklerden kolayca geçebilir. Bu nedenle süzme aşamasında ayrılmaz."},{"t":"Süzüntüdeki durumu","a":"Glikoz süzülür","d":"Glikoz küçük olduğundan ilk süzüntüye geçer ve süzüntüde bulunur. Ancak daha sonra proksimal tübülde geri emilir. Bu yüzden son idrarda normalde glikoz bulunmaz."}],"ans":"Evet, ilk süzüntüde glikoz bulunur (sonra geri emilir)."},{"q":"Glomerulusa kan getiren ve süzme için basıncı sağlayan damar hangisidir?","steps":[{"t":"Kan girişi","a":"Glomerulusa kan","d":"Glomerulusun süzme yapabilmesi için içine basınçlı kan getirilir. Bu kanı bir atardamar kolu sağlar. Kol glomerulusa girer."},{"t":"Damarın adı","a":"Getirici arteriol","d":"Glomerulusa kan getiren damar getirici arterioldür. Bu damar geniş olduğundan glomerulusa bol ve basınçlı kan ulaşır. Bu basınç süzme için gereklidir."}],"ans":"Getirici arteriol."},{"q":"Süzme sonucu kandan ayrılan sıvının içinde üre bulunur mu?","steps":[{"t":"Ürenin boyutu","a":"Küçük atık molekülü","d":"Üre, küçük bir azotlu atık molekülüdür. Süzme engelindeki gözeneklerden kolayca geçer. Süzme sırasında tutulmaz."},{"t":"Süzüntüdeki durumu","a":"Üre süzülür","d":"Üre küçük olduğundan süzüntüye geçer ve idrarla atılır. Çoğu üre geri emilmediğinden idrarda kalır. Böylece azotlu atık vücuttan uzaklaştırılır."}],"ans":"Evet, üre süzüntüde bulunur."},{"q":"Glomerulustaki süzme yapısının iki temel katmanı hangileridir?","steps":[{"t":"Süzme engelinin oluşumu","a":"İki yapı bir arada","d":"Süzme, kanın bulunduğu yapı ile süzüntünün toplandığı yapı arasında gerçekleşir. Bu iki yapının duvarları süzme engelini oluşturur. Sıvı bu engeli aşar."},{"t":"Katmanların adı","a":"Glomerulus duvarı ve Bowman kapsülü çeperi","d":"Süzme engeli, glomerulus kılcal damar duvarı ile Bowman kapsülünün iç çeperinden oluşur. Sıvı bu iki katmandan geçerek süzülür. Bu yapı küçük molekülleri geçirir, büyükleri tutar."}],"ans":"Glomerulus kılcal damar duvarı ve Bowman kapsülünün çeperi."},{"q":"Süzme olayında etkili olan basıncı kalpten gelen yüksek tansiyonla ilişkilendirebilir miyiz?","steps":[{"t":"Basıncın kaynağı","a":"Kalbin pompalaması","d":"Glomerulustaki yüksek basınç, son tahlilde kalbin kanı pompalamasından kaynaklanır. Kalp kanı yüksek basınçla aorta gönderir. Bu basınç böbrek atardamarına da aktarılır."},{"t":"İlişkilendirme","a":"Tansiyon süzmeyi etkiler","d":"Kan basıncı (tansiyon), glomerulustaki süzme basıncını doğrudan etkiler. Tansiyon düşerse süzme azalır, çok yükselirse süzme yapıları zarar görebilir. Bu yüzden kan basıncı süzmeyle yakından ilişkilidir."}],"ans":"Evet; kan basıncı (tansiyon) glomerulustaki süzme basıncını doğrudan etkiler."},{"q":"Glomerulustaki süzme suyun yanı sıra hangi maddeleri de geçirir?","steps":[{"t":"Geçen maddeler","a":"Küçük moleküller","d":"Glomerulustan su ile birlikte küçük moleküller de süzülür. Bunlar gözeneklerden geçebilen maddelerdir. Büyük moleküller geçemez."},{"t":"Madde örnekleri","a":"Glikoz, iyon, üre, aminoasit","d":"Su ile birlikte glikoz, mineral iyonları, üre ve aminoasitler de süzülür. Bunların bir kısmı sonra geri emilir. Atıklar ise büyük ölçüde idrarda kalır."}],"ans":"Glikoz, aminoasit, iyonlar ve üre gibi küçük moleküller."},{"q":"Glomerulustaki süzme işlemine pasif mi yoksa enerji gerektiren bir olay mı diyebiliriz?","steps":[{"t":"Sürecin doğası","a":"Basınçla itme","d":"Glomerulusta süzme, kan basıncının sıvıyı damar duvarından itmesiyle gerçekleşir. Burada itici güç fiziksel basınçtır. Hücreler madde taşıma için ATP harcamaz."},{"t":"Süreç türü","a":"Pasif (basınçla)","d":"Süzme, basınç farkıyla yürüdüğünden pasif bir olaydır ve doğrudan ATP gerektirmez. Buna karşın proksimal tübüldeki geri emilim aktif taşımayla olur. Bu iki olayın enerji gereksinimi farklıdır."}],"ans":"Pasif bir olaydır (kan basıncıyla gerçekleşir)."}],"zor":[{"q":"Kan basıncı ileri derecede düşen bir kişide idrar üretiminin azalması nasıl açıklanır?","steps":[{"t":"Süzmenin itici gücü","a":"Yüksek basınç gerekir","d":"Glomerulustaki süzme, kanın yüksek basıncıyla gerçekleşir. Basınç sıvıyı kandan Bowman kapsülüne iter. Süzme bu basınca bağlıdır."},{"t":"Basınç düşünce","a":"Süzme azalır","d":"Kan basıncı ileri derecede düşerse glomerulustaki süzme basıncı da düşer. Daha az sıvı süzülür. Süzüntü miktarı azalır."},{"t":"Sonuç","a":"İdrar üretimi azalır","d":"Süzüntü azalınca tübüllere giden sıvı ve sonuçta üretilen idrar da azalır. Bu yüzden düşük tansiyonda idrar miktarı düşer. Süzme basıncı doğrudan idrar üretimini belirler."}],"ans":"Süzme basıncı düşer, glomerulusta az sıvı süzülür, idrar azalır."},{"q":"İdrarda protein görülmesi (proteinüri) glomerulus hakkında ne düşündürür?","steps":[{"t":"Normal süzme","a":"Protein süzülmez","d":"Sağlıklı glomerulusta süzme engeli büyük protein moleküllerini geçirmez. Bu yüzden normal idrarda protein bulunmaz. Proteinler kanda kalır."},{"t":"Proteinin idrara geçmesi","a":"Engel bozulmuş","d":"İdrarda protein görülmesi, süzme engelinin gözeneklerinin büyüdüğünü ya da hasar gördüğünü gösterir. Bu durumda büyük moleküller de süzülür. Süzme seçiciliği bozulmuştur."},{"t":"Sonuç","a":"Glomerulus hasarı","d":"Proteinüri, çoğunlukla glomerulus süzme yapısının hasarına işaret eder. Bu, böbrek hastalığının bir bulgusu olabilir. Bu nedenle idrarda protein önemli bir belirtidir."}],"ans":"Glomerulus süzme yapısının hasar görüp seçiciliğini yitirdiğini düşündürür."},{"q":"İlk süzüntü ile son idrar arasındaki en büyük fark nedir, neden?","steps":[{"t":"İlk süzüntü","a":"Proteinsiz plazma","d":"İlk süzüntü, proteinler dışında plazmaya çok benzer; su, glikoz, iyon ve atık içerir. Hacmi çok büyüktür. Henüz geri emilim görmemiştir."},{"t":"Geri emilim etkisi","a":"Yararlı madde alınır","d":"Tübüllerde su, glikoz, aminoasit ve iyonların büyük kısmı geri emilir. Böylece süzüntü hem hacimce küçülür hem bileşimi değişir. Yararlı maddeler kana döner."},{"t":"Sonuç","a":"Son idrar yoğun atık","d":"Son idrar, ilk süzüntüye göre çok daha az hacimlidir ve atıklar bakımından yoğundur; glikoz içermez. Bu fark geri emilim ve salgılamadan kaynaklanır. İlk süzüntü ham, son idrar işlenmiş hâldir."}],"ans":"Son idrar çok daha az ve atıkça yoğundur; çünkü su ve yararlı maddeler geri emilmiştir."},{"q":"Yaklaşık 180 litre süzüntüden günde sadece 1-2 litre idrar oluşması süzme ve geri emilimle nasıl açıklanır?","steps":[{"t":"Süzüntü hacmi","a":"Çok büyük süzme","d":"Böbrekler gün boyunca çok büyük hacimde, yaklaşık 180 litre süzüntü üretir. Bu, kanın defalarca süzülmesiyle oluşur. Süzüntü hacmi idrardan çok daha fazladır."},{"t":"Geri emilim","a":"Suyun çoğu geri alınır","d":"Süzüntüdeki suyun ve yararlı maddelerin büyük kısmı tübüllerde geri emilir. Yaklaşık 178-179 litre su kana geri döner. Geriye az miktarda sıvı kalır."},{"t":"Sonuç","a":"1-2 litre idrar","d":"Yoğun geri emilim sonucu 180 litre süzüntüden yalnızca 1-2 litre idrar oluşur. Bu sayede su ve yararlı maddeler korunur, atıklar atılır. Süzme ve geri emilim birlikte bu büyük farkı yaratır."}],"ans":"Süzülen suyun yaklaşık %99'u geri emilir, geriye 1-2 litre idrar kalır."},{"q":"Glomerulustaki süzmenin basınçla, geri emilimin ise aktif taşımayla olması iki olayı nasıl ayırır?","steps":[{"t":"Süzmenin doğası","a":"Pasif, basınçla","d":"Glomerulustaki süzme, kan basıncının sıvıyı itmesiyle gerçekleşen pasif bir olaydır. Doğrudan ATP harcanmaz. İtici güç fizikseldir."},{"t":"Geri emilimin doğası","a":"Aktif, enerji ile","d":"Proksimal tübüldeki geri emilim, özellikle glikoz ve iyonlar için aktif taşıma gerektirir. Bu, ATP harcayan bir süreçtir. Maddeler derişim gradyanına karşı taşınabilir."},{"t":"Sonuç","a":"Enerji gereksinimi farkı","d":"Süzme pasif (enerjisiz), geri emilim ise büyük ölçüde aktif (enerjili) bir olaydır. Bu fark iki olayı temelde ayırır. Bu yüzden böbrek dokusu yoğun enerji ve oksijen kullanır."}],"ans":"Süzme pasif (basınçla), geri emilim ise aktif (ATP ile) gerçekleşir."},{"q":"Bir hastada kan proteinleri düşerse glomerulus süzmesi nasıl etkilenir?","steps":[{"t":"Plazma proteininin rolü","a":"Suyu kanda tutar","d":"Kan plazmasındaki proteinler, suyu damar içinde tutan bir çekme (ozmotik) etki yapar. Bu etki süzmeyi geri yönde dengeler. Proteinler süzmeye karşı bir kuvvet oluşturur."},{"t":"Protein azalınca","a":"Karşı kuvvet azalır","d":"Kan proteinleri azalırsa suyu tutan bu karşı kuvvet zayıflar. Süzmeye karşı koyan etki düşer. Süzme daha kolay gerçekleşir."},{"t":"Sonuç","a":"Süzme artabilir, ödem oluşur","d":"Karşı kuvvet azalınca süzme artabilir ve sıvı dokulara sızarak ödeme yol açabilir. Bu, plazma proteinlerinin süzme dengesindeki önemini gösterir. Süzme yalnızca kan basıncına değil, protein düzeyine de bağlıdır."}],"ans":"Suyu tutan karşı kuvvet azalır, süzme artar ve dokularda ödem gelişebilir."},{"q":"Süzme engelinin küçük molekülleri geçirip büyükleri tutması vücut için neden yararlıdır?","steps":[{"t":"Geçen maddeler","a":"Atık ve fazlalıklar","d":"Süzme engeli su, üre, fazla iyon gibi küçük molekülleri geçirir. Böylece atıklar ve fazlalıklar idrara aktarılabilir. Bu, atık atımının ilk adımıdır."},{"t":"Tutulan maddeler","a":"Değerli büyük moleküller","d":"Süzme engeli proteinleri ve kan hücrelerini tutar. Bu maddeler vücut için değerlidir ve kaybedilmemelidir. Engel onları kanda korur."},{"t":"Sonuç","a":"Atık atılır, değerli madde korunur","d":"Boyuta dayalı seçicilik, atıkların atılmasını sağlarken değerli maddeleri korur. Bu denge vücut için yaşamsaldır. Süzme engelinin seçiciliği bu nedenle çok yararlıdır."}],"ans":"Atıkların atılmasını sağlarken değerli protein ve hücreleri kanda korur."},{"q":"Glomerulus kılcal damarlarının iki arteriol arasında bulunması süzme basıncını nasıl korur?","steps":[{"t":"Olağan kılcal ağ","a":"Basınç düşer","d":"Vücuttaki çoğu kılcal damarda kan, atardamardan toplardamara akarken basınç giderek düşer. Bu, olağan kılcal ağların özelliğidir. Düşük basınç süzme için yetersizdir."},{"t":"Glomerulusun farkı","a":"İki arteriol arası","d":"Glomerulus, getirici ve götürücü arterioller arasında bulunur. Çıkıştaki götürücü arteriolün dar olması basıncın düşmesini engeller. Böylece glomerulusta basınç yüksek kalır."},{"t":"Sonuç","a":"Yüksek süzme basıncı","d":"İki arteriol arasında bulunma ve çıkışın dar olması, glomerulusta yüksek basıncın korunmasını sağlar. Bu yüksek basınç sürekli ve etkili süzme için gereklidir. Yapı, işleve uygun biçimde düzenlenmiştir."}],"ans":"İki arteriol arasında ve dar çıkışlı olması basıncı yüksek tutar, süzmeyi sürdürür."},{"q":"Böbreklerden günde çok büyük hacimde süzüntü geçmesi süzme hızının yüksekliğiyle nasıl ilişkilidir?","steps":[{"t":"Bol kanlanma","a":"Çok kan süzülür","d":"Böbrekler vücuttaki kanın önemli bir bölümünü sürekli süzer. Bol kanlanma çok miktarda kanın glomerulustan geçmesini sağlar. Bu, yüksek süzme hızının temelidir."},{"t":"Yüksek süzme hızı","a":"Büyük süzüntü hacmi","d":"Yüksek süzme hızı nedeniyle günde yaklaşık 180 litre süzüntü oluşur. Bu büyük hacim, kanın defalarca süzülmesiyle birikir. Süzme hızı süzüntü hacmini belirler."},{"t":"Sonuç","a":"Etkili atık temizliği","d":"Yüksek süzme hızı, atıkların hızlı ve etkili biçimde uzaklaştırılmasını sağlar. Geri emilim ise gerekli maddeleri korur. Böylece büyük süzüntü hacmi vücut için bir sorun değil, avantajdır."}],"ans":"Yüksek süzme hızı sayesinde günde çok büyük hacimde süzüntü oluşur, atıklar hızla temizlenir."},{"q":"Glomerulusta süzülen sıvıda kan hücresi ve protein bulunmaması idrarın hangi özelliğiyle açıklanır?","steps":[{"t":"Süzme seçiciliği","a":"Boyut engeli","d":"Glomerulustaki süzme engeli yalnızca küçük molekülleri geçirir. Kan hücreleri ve proteinler büyük olduğundan geçemez. Bu seçicilik süzüntünün bileşimini belirler."},{"t":"Süzüntünün içeriği","a":"Hücre ve proteinsiz","d":"Sonuçta süzüntü kan hücreleri ve proteinlerden yoksun, proteinsiz plazma benzeri bir sıvı olur. Tübüllerde işlenerek idrara dönüşür. Hücre ve protein normalde idrara geçmez."},{"t":"Sonuç","a":"Normal idrarda yok","d":"Bu seçicilik nedeniyle sağlıklı idrarda kan hücresi ve protein bulunmaz. Bunların idrarda görülmesi süzme yapısının hasarına işaret eder. Süzme engelinin sağlamlığı idrarın temizliğini belirler."}],"ans":"Süzme engeli büyük olan hücre ve proteinleri tutar; normal idrarda bunlar bulunmaz."},{"q":"Süzmenin sürekli olması ile böbreklerin yüksek miktarda enerji harcaması arasında nasıl bir bağ vardır?","steps":[{"t":"Süzme süreklidir","a":"Durmadan süzme","d":"Böbrekler gün boyu durmadan kan süzer ve büyük hacimde süzüntü üretir. Süzme pasif olsa da çok miktarda sıvı işlenir. Bu sürekliliğin bir bedeli vardır."},{"t":"Geri emilim yükü","a":"Çok madde geri alınır","d":"Büyük süzüntü hacmindeki su ve yararlı maddelerin geri emilmesi gerekir. Bu geri emilim aktif taşımayla yapılır ve ATP harcar. Süzme ne kadar çoksa geri emilim de o kadar çok olur."},{"t":"Sonuç","a":"Yüksek enerji tüketimi","d":"Sürekli ve bol süzme, geri emilim için yoğun enerji gerektirir. Bu yüzden böbrekler vücudun en çok enerji ve oksijen kullanan organlarındandır. Süzme ile enerji harcaması doğrudan ilişkilidir."}],"ans":"Bol süzüntünün geri emilimi aktif taşıma (ATP) gerektirir, bu da yüksek enerji tüketimine yol açar."},{"q":"Aşırı yüksek kan basıncının (hipertansiyon) uzun süre glomerulusa zarar vermesi nasıl açıklanır?","steps":[{"t":"Süzme ve basınç","a":"Basınç süzmeyi yürütür","d":"Glomerulustaki süzme, kanın basıncıyla gerçekleşir. Normal basınç süzme için gereklidir. Ancak basıncın aşırı yükselmesi sorun yaratır."},{"t":"Aşırı basınç etkisi","a":"İnce yapılar zorlanır","d":"Glomerulusun ince kılcal damar duvarları çok yüksek basınca uzun süre dayanamaz. Aşırı basınç bu narin yapıları zedeler. Süzme engeli zamanla bozulur."},{"t":"Sonuç","a":"Glomerulus hasarı","d":"Uzun süreli yüksek tansiyon glomerulus yapısına kalıcı zarar verir ve süzme bozulur. Bu, böbrek yetmezliğine giden bir yol olabilir. Bu nedenle tansiyon kontrolü böbrek sağlığı için önemlidir."}],"ans":"Aşırı basınç ince glomerulus kılcal damarlarını zamanla zedeler, süzme bozulur."},{"q":"Süzüntünün plazmaya çok benzemesi ama proteinden yoksun olması süzme mekanizması hakkında ne söyler?","steps":[{"t":"Plazma ile benzerlik","a":"Küçük moleküller ortak","d":"Süzüntü, su, glikoz, iyon ve üre gibi küçük moleküller bakımından plazmaya çok benzer. Çünkü bu maddeler süzme engelinden geçer. Süzme küçükleri geçirir."},{"t":"Proteinden yoksunluk","a":"Büyük molekül tutulur","d":"Süzüntü proteinden yoksundur çünkü proteinler büyük olup süzme engelinden geçemez. Bu fark, süzmenin boyuta dayalı olduğunu gösterir. Engel büyükleri eler."},{"t":"Sonuç","a":"Boyuta dayalı süzme","d":"Süzüntünün plazmaya benzeyip proteinsiz olması, süzmenin molekül büyüklüğüne göre çalıştığını kanıtlar. Küçük moleküller geçer, büyükler kalır. Bu, süzme mekanizmasının temel ilkesidir."}],"ans":"Süzmenin molekül büyüklüğüne dayalı (boyut seçici) olduğunu gösterir."},{"q":"Bir böbrekte glomerulus sayısı azalırsa toplam süzme hacmi nasıl etkilenir?","steps":[{"t":"Glomerulus ve süzme","a":"Her biri süzer","d":"Her glomerulus belirli miktarda kan süzer. Toplam süzme, çalışan glomerulusların toplamına bağlıdır. Çok glomerulus, çok süzme demektir."},{"t":"Sayı azalınca","a":"Toplam süzme düşer","d":"Glomerulus sayısı azalırsa toplam süzme yüzeyi ve kapasitesi azalır. Kalan glomeruluslar daha çok yüklenir. Toplam süzme hacmi düşer."},{"t":"Sonuç","a":"Süzme hacmi azalır","d":"Glomerulus sayısının azalması böbreğin toplam süzme hacmini düşürür. Bu, atık atma gücünü zayıflatır. Süzme kapasitesi glomerulus sayısıyla orantılıdır."}],"ans":"Çalışan glomerulus sayısı azalınca toplam süzme hacmi düşer."},{"q":"Glomerulustaki süzmenin atık atımı ile fazla suyun atımını aynı anda sağlaması neden önemlidir?","steps":[{"t":"Süzülen içerik","a":"Su ve atık birlikte","d":"Glomerulusta su ile birlikte üre gibi atıklar da süzülür. Yani süzme hem suyu hem atığı kandan ayırır. İkisi aynı süzüntüde bulunur."},{"t":"İki görevin birleşmesi","a":"Hem atık hem su atımı","d":"Bu sayede böbrek aynı anda hem azotlu atıkları uzaklaştırır hem de fazla suyu atabilir. Geri emilimle gerekli su tutulur. Böylece denge sağlanır."},{"t":"Sonuç","a":"İç denge korunur","d":"Süzmenin su ve atığı birlikte ayırması, atık atımı ile su dengesinin birlikte yürütülmesini sağlar. Bu, iç ortam kararlılığı için önemlidir. Tek bir süzme olayı iki yaşamsal görevi destekler."}],"ans":"Tek süzme olayıyla hem azotlu atıklar hem de fazla su kandan ayrılır, iç denge korunur."}]}}};
